"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import {
  Sparkles,
  Edit2,
  AlertTriangle,
  Droplets,
  Palette,
  Heart,
  Save,
  X,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type { CustomerBeautyProfile, HairType } from "@/lib/data/types";
import { hairTypeLabels } from "@/lib/data/mock/beautyHistory";

interface BeautyProfileCardProps {
  profile: CustomerBeautyProfile;
  onSave: (profile: CustomerBeautyProfile) => void;
}

const hairTypeOptions: { value: HairType | ""; label: string }[] = [
  { value: "", label: "انتخاب نشده" },
  { value: "oily", label: "چرب" },
  { value: "dry", label: "خشک" },
  { value: "normal", label: "معمولی" },
  { value: "damaged", label: "آسیب‌دیده" },
];

export default function BeautyProfileCard({
  profile,
  onSave,
}: BeautyProfileCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [form, setForm] = useState(profile);

  const hasSensitivities = !!profile.sensitivities.trim();
  const isEmpty =
    !profile.hairType &&
    !profile.currentHairColor &&
    !profile.sensitivities &&
    !profile.preferences &&
    !profile.notes;

  const handleStartEdit = () => {
    setForm(profile);
    setIsEditing(true);
  };

  const handleCancel = () => {
    setForm(profile);
    setIsEditing(false);
  };

  const handleSave = () => {
    onSave({
      ...form,
      updatedAt: "همین الان",
    });
    setIsEditing(false);
  };

  return (
    <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
      <div className="flex items-center justify-between p-5 border-b border-[#2A2A3A]">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5 flex items-center justify-center">
            <Sparkles size={20} className="text-[#C9A96E]" />
          </div>
          <div>
            <h2 className="text-lg font-bold text-[#F5F0E8]">پروفایل زیبایی</h2>
            <p className="text-xs text-[#A09880]">
              اطلاعات پایدار مشتری — نوع مو، حساسیت‌ها و ترجیحات
            </p>
          </div>
        </div>

        {!isEditing ? (
          <button
            onClick={handleStartEdit}
            className="btn-outline-gold px-3 py-2 text-sm font-medium flex items-center gap-2"
          >
            <Edit2 size={14} />
            ویرایش
          </button>
        ) : (
          <div className="flex items-center gap-2">
            <button
              onClick={handleCancel}
              className="px-3 py-2 rounded-xl text-sm text-[#A09880] hover:text-[#F5F0E8] hover:bg-white/5 transition-colors flex items-center gap-1"
            >
              <X size={14} />
              انصراف
            </button>
            <button
              onClick={handleSave}
              className="btn-gold px-3 py-2 text-sm font-bold flex items-center gap-1"
            >
              <Save size={14} />
              ذخیره
            </button>
          </div>
        )}
      </div>

      {hasSensitivities && !isEditing && (
        <div className="mx-5 mt-5 p-4 rounded-xl bg-[#E05555]/10 border border-[#E05555]/20 flex items-start gap-3">
          <AlertTriangle size={18} className="text-[#E05555] shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-medium text-[#E05555] mb-1">حساسیت / آلرژی</p>
            <p className="text-sm text-[#F5F0E8]/80">{profile.sensitivities}</p>
          </div>
        </div>
      )}

      <div className="p-5">
        {isEditing ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-[#A09880] mb-2">
                نوع مو
              </label>
              <select
                value={form.hairType ?? ""}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    hairType: (e.target.value || null) as HairType | null,
                  }))
                }
                className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] focus:outline-none focus:border-[#C9A96E]/50 transition-colors"
              >
                {hairTypeOptions.map((opt) => (
                  <option key={opt.value} value={opt.value} className="bg-[#12121A]">
                    {opt.label}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-[#A09880] mb-2">
                رنگ فعلی مو
              </label>
              <input
                type="text"
                value={form.currentHairColor}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, currentHairColor: e.target.value }))
                }
                placeholder="مثال: بلوند دودی شماره ۷"
                className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors"
              />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-sm font-medium text-[#A09880] mb-2">
                حساسیت‌ها و آلرژی‌ها
              </label>
              <textarea
                value={form.sensitivities}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, sensitivities: e.target.value }))
                }
                placeholder="مثال: حساسیت به محصولات آمونیاک‌دار..."
                rows={2}
                className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors resize-none"
              />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-sm font-medium text-[#A09880] mb-2">
                ترجیحات مشتری
              </label>
              <textarea
                value={form.preferences}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, preferences: e.target.value }))
                }
                placeholder="مثال: پوشش کامل ریشه، ترجیح کوتاهی کلاسیک..."
                rows={2}
                className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors resize-none"
              />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-sm font-medium text-[#A09880] mb-2">
                یادداشت عمومی
              </label>
              <textarea
                value={form.notes}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, notes: e.target.value }))
                }
                placeholder="یادداشت‌های کلی درباره مشتری..."
                rows={2}
                className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors resize-none"
              />
            </div>
          </div>
        ) : isEmpty ? (
          <div className="py-8 text-center">
            <Sparkles size={40} className="mx-auto text-[#A09880]/50 mb-3" />
            <p className="text-sm text-[#A09880] mb-4">
              پروفایل زیبایی این مشتری هنوز تکمیل نشده است.
            </p>
            <button onClick={handleStartEdit} className="btn-gold px-5 py-2 text-sm font-bold">
              تکمیل پروفایل
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {profile.hairType && (
              <ProfileField
                icon={Droplets}
                label="نوع مو"
                value={hairTypeLabels[profile.hairType]}
              />
            )}
            {profile.currentHairColor && (
              <ProfileField
                icon={Palette}
                label="رنگ فعلی"
                value={profile.currentHairColor}
              />
            )}
            {profile.preferences && (
              <ProfileField
                icon={Heart}
                label="ترجیحات"
                value={profile.preferences}
                className="sm:col-span-2 lg:col-span-1"
              />
            )}
            {profile.notes && (
              <ProfileField
                icon={Sparkles}
                label="یادداشت"
                value={profile.notes}
                className="sm:col-span-2"
              />
            )}
          </div>
        )}

        {!isEditing && !isEmpty && (
          <p className="mt-4 text-xs text-[#A09880]">
            آخرین بروزرسانی: {profile.updatedAt}
          </p>
        )}
      </div>
    </div>
  );
}

function ProfileField({
  icon: Icon,
  label,
  value,
  className,
}: {
  icon: React.ComponentType<{ size?: number; className?: string }>;
  label: string;
  value: string;
  className?: string;
}) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      className={cn("p-4 rounded-xl bg-white/5 border border-white/5", className)}
    >
      <div className="flex items-center gap-2 text-[#C9A96E] mb-2">
        <Icon size={14} />
        <span className="text-xs font-medium">{label}</span>
      </div>
      <p className="text-sm text-[#F5F0E8] leading-relaxed">{value}</p>
    </motion.div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, BookOpen, Calendar, User, Scissors } from "lucide-react";
import LoadingSpinner from "@/components/shared/LoadingSpinner";
import type { BeautyHistoryEntry, Service, Staff } from "@/lib/data/types";

export type BeautyHistoryFormData = Omit<
  BeautyHistoryEntry,
  "id" | "createdAt" | "staffName" | "serviceName"
>;

interface BeautyHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: BeautyHistoryFormData) => void;
  initialData?: BeautyHistoryEntry | null;
  customerId: string;
  staffList: Staff[];
  serviceList: Service[];
  isLoading?: boolean;
}

const emptyForm = (customerId: string): BeautyHistoryFormData => ({
  customerId,
  appointmentId: null,
  date: "",
  staffId: "",
  serviceId: "",
  formulasUsed: "",
  techniquesApplied: "",
  clientPreferences: "",
  sensitivitiesNoted: "",
  resultNotes: "",
  nextVisitRecommendation: "",
});

export default function BeautyHistoryModal({
  isOpen,
  onClose,
  onSave,
  initialData,
  customerId,
  staffList,
  serviceList,
  isLoading = false,
}: BeautyHistoryModalProps) {
  const [form, setForm] = useState<BeautyHistoryFormData>(emptyForm(customerId));
  const [errors, setErrors] = useState<Partial<Record<string, string>>>({});

  const isEditing = !!initialData?.id;

  useEffect(() => {
    if (initialData) {
      setForm({
        customerId: initialData.customerId,
        appointmentId: initialData.appointmentId,
        date: initialData.date,
        staffId: initialData.staffId,
        serviceId: initialData.serviceId,
        formulasUsed: initialData.formulasUsed,
        techniquesApplied: initialData.techniquesApplied,
        clientPreferences: initialData.clientPreferences,
        sensitivitiesNoted: initialData.sensitivitiesNoted,
        resultNotes: initialData.resultNotes,
        nextVisitRecommendation: initialData.nextVisitRecommendation,
      });
    } else {
      setForm(emptyForm(customerId));
    }
    setErrors({});
  }, [initialData, isOpen, customerId]);

  const validate = (): boolean => {
    const next: Partial<Record<string, string>> = {};
    if (!form.date.trim()) next.date = "تاریخ الزامی است";
    if (!form.staffId) next.staffId = "انتخاب آرایشگر الزامی است";
    if (!form.serviceId) next.serviceId = "انتخاب سرویس الزامی است";
    setErrors(next);
    return Object.keys(next).length === 0;
  };

  const handleSubmit = () => {
    if (validate()) onSave(form);
  };

  const activeStaff = staffList.filter((s) => s.isActive);
  const activeServices = serviceList.filter((s) => s.isActive);

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4 py-6 overflow-y-auto"
        >
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ duration: 0.2 }}
            className="w-full max-w-lg bg-[#12121A] border border-white/10 rounded-2xl overflow-hidden my-auto"
          >
            <div className="flex items-center justify-between p-6 border-b border-[#2A2A3A]">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5 flex items-center justify-center">
                  <BookOpen size={20} className="text-[#C9A96E]" />
                </div>
                <h2 className="text-lg font-bold text-[#F5F0E8]">
                  {isEditing ? "ویرایش یادداشت کارنامه" : "یادداشت جدید کارنامه زیبایی"}
                </h2>
              </div>
              <button
                onClick={onClose}
                className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-[#A09880] hover:text-[#F5F0E8] transition-colors"
              >
                <X size={18} />
              </button>
            </div>

            <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-[#A09880] mb-2">
                    <Calendar size={12} className="inline ml-1" />
                    تاریخ مراجعه <span className="text-[#E05555]">*</span>
                  </label>
                  <input
                    type="text"
                    value={form.date}
                    onChange={(e) => setForm((p) => ({ ...p, date: e.target.value }))}
                    placeholder="۱۴۰۳/۱۰/۱۵"
                    className={`w-full px-4 py-3 rounded-xl bg-white/5 border text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none transition-colors ${
                      errors.date
                        ? "border-[#E05555]/50"
                        : "border-white/10 focus:border-[#C9A96E]/50"
                    }`}
                  />
                  {errors.date && (
                    <p className="mt-1 text-xs text-[#E05555]">{errors.date}</p>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-medium text-[#A09880] mb-2">
                    <User size={12} className="inline ml-1" />
                    آرایشگر <span className="text-[#E05555]">*</span>
                  </label>
                  <select
                    value={form.staffId}
                    onChange={(e) => setForm((p) => ({ ...p, staffId: e.target.value }))}
                    className={`w-full px-4 py-3 rounded-xl bg-white/5 border text-[#F5F0E8] focus:outline-none transition-colors appearance-none ${
                      errors.staffId
                        ? "border-[#E05555]/50"
                        : "border-white/10 focus:border-[#C9A96E]/50"
                    }`}
                  >
                    <option value="" className="bg-[#12121A]">
                      انتخاب آرایشگر
                    </option>
                    {activeStaff.map((s) => (
                      <option key={s.id} value={s.id} className="bg-[#12121A]">
                        {s.name}
                      </option>
                    ))}
                  </select>
                  {errors.staffId && (
                    <p className="mt-1 text-xs text-[#E05555]">{errors.staffId}</p>
                  )}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-[#A09880] mb-2">
                  <Scissors size={12} className="inline ml-1" />
                  سرویس <span className="text-[#E05555]">*</span>
                </label>
                <select
                  value={form.serviceId}
                  onChange={(e) => setForm((p) => ({ ...p, serviceId: e.target.value }))}
                  className={`w-full px-4 py-3 rounded-xl bg-white/5 border text-[#F5F0E8] focus:outline-none transition-colors appearance-none ${
                    errors.serviceId
                      ? "border-[#E05555]/50"
                      : "border-white/10 focus:border-[#C9A96E]/50"
                  }`}
                >
                  <option value="" className="bg-[#12121A]">
                    انتخاب سرویس
                  </option>
                  {activeServices.map((s) => (
                    <option key={s.id} value={s.id} className="bg-[#12121A]">
                      {s.name}
                    </option>
                  ))}
                </select>
                {errors.serviceId && (
                  <p className="mt-1 text-xs text-[#E05555]">{errors.serviceId}</p>
                )}
              </div>

              <Field
                label="فرمول / مواد استفاده‌شده"
                value={form.formulasUsed}
                onChange={(v) => setForm((p) => ({ ...p, formulasUsed: v }))}
                placeholder="مثال: بلوند شماره ۷ + اکسیدان ۲۰ vol"
              />
              <Field
                label="تکنیک و روش کار"
                value={form.techniquesApplied}
                onChange={(v) => setForm((p) => ({ ...p, techniquesApplied: v }))}
                placeholder="مثال: رنگ ریشه + گلایس روی طول مو"
              />
              <Field
                label="ترجیحات مشتری در این جلسه"
                value={form.clientPreferences}
                onChange={(v) => setForm((p) => ({ ...p, clientPreferences: v }))}
                placeholder="مثال: پوشش کامل ریشه"
              />
              <Field
                label="حساسیت‌های ثبت‌شده"
                value={form.sensitivitiesNoted}
                onChange={(v) => setForm((p) => ({ ...p, sensitivitiesNoted: v }))}
                placeholder="اگر واکنش یا حساسیتی بود اینجا بنویسید"
              />
              <Field
                label="نتیجه و بازخورد"
                value={form.resultNotes}
                onChange={(v) => setForm((p) => ({ ...p, resultNotes: v }))}
                placeholder="نتیجه کار و رضایت مشتری"
              />
              <Field
                label="توصیه برای مراجعه بعدی"
                value={form.nextVisitRecommendation}
                onChange={(v) => setForm((p) => ({ ...p, nextVisitRecommendation: v }))}
                placeholder="مثال: ۶ هفته دیگر برای بازبینی ریشه"
              />
            </div>

            <div className="flex items-center gap-3 p-6 border-t border-[#2A2A3A]">
              <button
                onClick={onClose}
                className="flex-1 px-4 py-3 rounded-xl text-[#A09880] hover:text-[#F5F0E8] hover:bg-white/5 transition-colors font-medium"
              >
                انصراف
              </button>
              <button
                onClick={handleSubmit}
                disabled={isLoading}
                className="flex-1 btn-gold px-4 py-3 font-bold flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isLoading ? <LoadingSpinner size={20} /> : "ذخیره یادداشت"}
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

function Field({
  label,
  value,
  onChange,
  placeholder,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
}) {
  return (
    <div>
      <label className="block text-sm font-medium text-[#A09880] mb-2">{label}</label>
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        rows={2}
        className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors resize-none"
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  BookOpen,
  Plus,
  Edit2,
  Trash2,
  ChevronDown,
  Calendar,
  User,
  FlaskConical,
  AlertTriangle,
  Clock,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type { BeautyHistoryEntry, CustomerBeautyProfile } from "@/lib/data/types";
import type { Service, Staff } from "@/lib/data/types";
import BeautyProfileCard from "./BeautyProfileCard";
import BeautyHistoryModal, {
  type BeautyHistoryFormData,
} from "./BeautyHistoryModal";

interface BeautyHistorySectionProps {
  customerId: string;
  profile: CustomerBeautyProfile;
  entries: BeautyHistoryEntry[];
  staffList: Staff[];
  serviceList: Service[];
  onSaveProfile: (profile: CustomerBeautyProfile) => void;
  onAddEntry: (data: BeautyHistoryFormData) => void;
  onUpdateEntry: (entry: BeautyHistoryEntry) => void;
  onRemoveEntry: (id: string) => void;
}

export default function BeautyHistorySection({
  customerId,
  profile,
  entries,
  staffList,
  serviceList,
  onSaveProfile,
  onAddEntry,
  onUpdateEntry,
  onRemoveEntry,
}: BeautyHistorySectionProps) {
  const [modalOpen, setModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<BeautyHistoryEntry | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(
    entries[0]?.id ?? null
  );

  const handleOpenAdd = () => {
    setEditingEntry(null);
    setModalOpen(true);
  };

  const handleOpenEdit = (entry: BeautyHistoryEntry) => {
    setEditingEntry(entry);
    setModalOpen(true);
  };

  const handleSave = async (data: BeautyHistoryFormData) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 400));

    const staff = staffList.find((s) => s.id === data.staffId);
    const service = serviceList.find((s) => s.id === data.serviceId);

    if (editingEntry) {
      onUpdateEntry({
        ...editingEntry,
        ...data,
        staffName: staff?.name ?? editingEntry.staffName,
        serviceName: service?.name ?? editingEntry.serviceName,
      });
    } else {
      onAddEntry({
        ...data,
        staffName: staff?.name ?? "",
        serviceName: service?.name ?? "",
      } as BeautyHistoryFormData & { staffName: string; serviceName: string });
    }

    setIsLoading(false);
    setModalOpen(false);
    setEditingEntry(null);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("آیا از حذف این یادداشت کارنامه مطمئن هستید؟")) {
      onRemoveEntry(id);
      if (expandedId === id) setExpandedId(null);
    }
  };

  return (
    <div className="space-y-6">
      <BeautyProfileCard profile={profile} onSave={onSaveProfile} />

      <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
        <div className="flex items-center justify-between p-5 border-b border-[#2A2A3A]">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5 flex items-center justify-center">
              <BookOpen size={20} className="text-[#C9A96E]" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-[#F5F0E8]">سابقه کارنامه زیبایی</h2>
              <p className="text-xs text-[#A09880]">
                {entries.length} یادداشت ثبت‌شده — فرمول‌ها، تکنیک‌ها و نتایج هر جلسه
              </p>
            </div>
          </div>
          <button
            onClick={handleOpenAdd}
            className="btn-gold px-4 py-2 text-sm font-bold flex items-center gap-2"
          >
            <Plus size={16} />
            یادداشت جدید
          </button>
        </div>

        <div className="p-4">
          {entries.length === 0 ? (
            <div className="py-12 text-center">
              <BookOpen size={48} className="mx-auto text-[#A09880]/50 mb-4" />
              <h3 className="text-lg font-bold text-[#F5F0E8] mb-2">
                هنوز یادداشتی ثبت نشده
              </h3>
              <p className="text-sm text-[#A09880] mb-6 max-w-md mx-auto">
                بعد از هر مراجعه، فرمول رنگ، تکنیک کار و ترجیحات مشتری را اینجا ثبت
                کنید تا دفعه بعد دقیقاً بدانید چه کاری انجام شده.
              </p>
              <button onClick={handleOpenAdd} className="btn-gold px-6 py-2.5 text-sm font-bold">
                ثبت اولین یادداشت
              </button>
            </div>
          ) : (
            <div className="space-y-3">
              {entries.map((entry, i) => (
                <HistoryEntryCard
                  key={entry.id}
                  entry={entry}
                  index={i}
                  isExpanded={expandedId === entry.id}
                  onToggle={() =>
                    setExpandedId(expandedId === entry.id ? null : entry.id)
                  }
                  onEdit={() => handleOpenEdit(entry)}
                  onDelete={() => handleDelete(entry.id)}
                />
              ))}
            </div>
          )}
        </div>
      </div>

      <BeautyHistoryModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingEntry(null);
        }}
        onSave={handleSave}
        initialData={editingEntry}
        customerId={customerId}
        staffList={staffList}
        serviceList={serviceList}
        isLoading={isLoading}
      />
    </div>
  );
}

function HistoryEntryCard({
  entry,
  index,
  isExpanded,
  onToggle,
  onEdit,
  onDelete,
}: {
  entry: BeautyHistoryEntry;
  index: number;
  isExpanded: boolean;
  onToggle: () => void;
  onEdit: () => void;
  onDelete: () => void;
}) {
  const hasSensitivity =
    entry.sensitivitiesNoted.trim() && entry.sensitivitiesNoted !== "—";

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.04 }}
      className="rounded-xl bg-white/5 border border-white/5 overflow-hidden"
    >
      <button
        onClick={onToggle}
        className="w-full flex items-center gap-4 p-4 text-right hover:bg-white/[0.04] transition-colors"
      >
        <div className="text-center min-w-[56px] shrink-0">
          <div className="text-xs text-[#C9A96E] font-medium">{entry.date}</div>
        </div>

        <div className="w-px h-10 bg-[#2A2A3A] shrink-0" />

        <div className="flex-1 min-w-0">
          <p className="font-medium text-[#F5F0E8] truncate">{entry.serviceName}</p>
          <p className="text-xs text-[#A09880]">{entry.staffName}</p>
        </div>

        {hasSensitivity && (
          <span className="hidden sm:flex items-center gap-1 px-2 py-1 rounded-lg bg-[#E05555]/10 text-[#E05555] text-xs shrink-0">
            <AlertTriangle size={12} />
            حساسیت
          </span>
        )}

        {entry.nextVisitRecommendation &&
          entry.nextVisitRecommendation !== "—" && (
            <span className="hidden md:flex items-center gap-1 px-2 py-1 rounded-lg bg-[#3B82F6]/10 text-[#3B82F6] text-xs shrink-0">
              <Clock size={12} />
              {entry.nextVisitRecommendation}
            </span>
          )}

        <ChevronDown
          size={18}
          className={cn(
            "text-[#A09880] shrink-0 transition-transform",
            isExpanded && "rotate-180"
          )}
        />
      </button>

      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="overflow-hidden"
          >
            <div className="px-4 pb-4 pt-0 border-t border-[#2A2A3A]/50">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">
                <DetailField
                  icon={Calendar}
                  label="تاریخ"
                  value={entry.date}
                />
                <DetailField icon={User} label="آرایشگر" value={entry.staffName} />
                {entry.formulasUsed && entry.formulasUsed !== "—" && (
                  <DetailField
                    icon={FlaskConical}
                    label="فرمول / مواد"
                    value={entry.formulasUsed}
                    className="sm:col-span-2"
                  />
                )}
                {entry.techniquesApplied && (
                  <DetailField
                    label="تکنیک"
                    value={entry.techniquesApplied}
                    className="sm:col-span-2"
                  />
                )}
                {entry.clientPreferences && (
                  <DetailField
                    label="ترجیحات جلسه"
                    value={entry.clientPreferences}
                    className="sm:col-span-2"
                  />
                )}
                {hasSensitivity && (
                  <DetailField
                    icon={AlertTriangle}
                    label="حساسیت"
                    value={entry.sensitivitiesNoted}
                    className="sm:col-span-2"
                    highlight
                  />
                )}
                {entry.resultNotes && (
                  <DetailField
                    label="نتیجه"
                    value={entry.resultNotes}
                    className="sm:col-span-2"
                  />
                )}
                {entry.nextVisitRecommendation &&
                  entry.nextVisitRecommendation !== "—" && (
                    <DetailField
                      icon={Clock}
                      label="مراجعه بعدی"
                      value={entry.nextVisitRecommendation}
                      className="sm:col-span-2"
                    />
                  )}
              </div>

              <div className="flex items-center gap-2 mt-4 pt-4 border-t border-[#2A2A3A]/50">
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onEdit();
                  }}
                  className="px-3 py-1.5 rounded-lg bg-white/5 text-sm text-[#A09880] hover:text-[#C9A96E] hover:bg-[#C9A96E]/10 transition-colors flex items-center gap-1"
                >
                  <Edit2 size={14} />
                  ویرایش
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onDelete();
                  }}
                  className="px-3 py-1.5 rounded-lg bg-white/5 text-sm text-[#A09880] hover:text-[#E05555] hover:bg-[#E05555]/10 transition-colors flex items-center gap-1"
                >
                  <Trash2 size={14} />
                  حذف
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

function DetailField({
  icon: Icon,
  label,
  value,
  className,
  highlight,
}: {
  icon?: React.ComponentType<{ size?: number; className?: string }>;
  label: string;
  value: string;
  className?: string;
  highlight?: boolean;
}) {
  return (
    <div
      className={cn(
        "p-3 rounded-lg bg-white/[0.03]",
        highlight && "bg-[#E05555]/5 border border-[#E05555]/10",
        className
      )}
    >
      <div
        className={cn(
          "flex items-center gap-1.5 text-xs mb-1",
          highlight ? "text-[#E05555]" : "text-[#C9A96E]"
        )}
      >
        {Icon && <Icon size={12} />}
        <span>{label}</span>
      </div>
      <p className="text-sm text-[#F5F0E8]/90 leading-relaxed">{value}</p>
    </div>
  );
}

