"use client";

import { useState } from "react";
import Link from "next/link";
import { motion } from "framer-motion";
import {
  ArrowRight,
  Edit2,
  Plus,
  Calendar,
  Clock,
  Phone,
  CalendarDays,
  StickyNote,
  CalendarX,
  BookOpen,
  AlertTriangle,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type {
  AppointmentStatus,
  CustomerProfile,
} from "@/lib/data/mock/customerProfiles";
import BeautyHistorySection from "@/components/admin/BeautyHistorySection";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  addBeautyHistoryEntry,
  removeBeautyHistoryEntry,
  selectAdminServices,
  selectAdminStaff,
  selectBeautyHistoryByCustomerId,
  selectBeautyProfileByCustomerId,
  updateBeautyHistoryEntry,
  upsertBeautyProfile,
} from "@/store/slices/adminSlice";

const statusConfig: Record<
  AppointmentStatus,
  { label: string; color: string; bg: string }
> = {
  pending: { label: "رزرو شده", color: "text-[#3B82F6]", bg: "bg-[#3B82F6]/10" },
  confirmed: { label: "تأیید شده", color: "text-[#4CAF82]", bg: "bg-[#4CAF82]/10" },
  completed: { label: "انجام شده", color: "text-[#A09880]", bg: "bg-[#A09880]/10" },
  cancelled: { label: "لغو شده", color: "text-[#E05555]", bg: "bg-[#E05555]/10" },
  no_show: { label: "غیبت", color: "text-[#E8A84C]", bg: "bg-[#E8A84C]/10" },
};

function getAvatarColor(name: string): string {
  const colors = [
    "from-[#C9A96E] to-[#E8C98A]",
    "from-[#3B82F6] to-[#60A5FA]",
    "from-[#4CAF82] to-[#6FCF97]",
  ];
  const index = name.charCodeAt(0) % colors.length;
  return colors[index];
}

type Tab = "upcoming" | "history" | "beauty";

interface CustomerProfileClientProps {
  customer: CustomerProfile;
}

export default function CustomerProfileClient({
  customer,
}: CustomerProfileClientProps) {
  const dispatch = useAppDispatch();
  const [activeTab, setActiveTab] = useState<Tab>("upcoming");

  const customerId = customer.id;
  const beautyProfile = useAppSelector(selectBeautyProfileByCustomerId(customerId));
  const beautyHistory = useAppSelector(selectBeautyHistoryByCustomerId(customerId));
  const staffList = useAppSelector(selectAdminStaff);
  const serviceList = useAppSelector(selectAdminServices);

  const appointments =
    activeTab === "upcoming"
      ? customer.upcomingAppointments
      : customer.pastAppointments;

  const hasSensitivities = !!beautyProfile.sensitivities.trim();
  const historyCount = beautyHistory.length;

  const tabs: { id: Tab; label: string; badge?: number }[] = [
    { id: "upcoming", label: "نوبت‌های آینده" },
    { id: "history", label: "تاریخچه نوبت‌ها" },
    { id: "beauty", label: "کارنامه زیبایی", badge: historyCount || undefined },
  ];

  return (
    <div className="space-y-6">
      <Link
        href="/admin/customers"
        className="inline-flex items-center gap-2 text-sm text-[#A09880] hover:text-[#C9A96E] transition-colors"
      >
        <ArrowRight size={16} />
        بازگشت به لیست مشتریان
      </Link>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 p-6"
      >
        <div className="flex flex-col md:flex-row md:items-start gap-6">
          <div
            className={cn(
              "w-20 h-20 rounded-2xl bg-gradient-to-br flex items-center justify-center text-[#0A0A0F] text-3xl font-bold",
              getAvatarColor(customer.name)
            )}
          >
            {customer.name.charAt(0)}
          </div>

          <div className="flex-1">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-4">
              <div>
                <h1 className="text-2xl font-bold text-[#F5F0E8] mb-1">
                  {customer.name}
                </h1>
                <div className="flex items-center gap-2 text-[#A09880]">
                  <Phone size={14} />
                  <span dir="ltr">{customer.phone}</span>
                </div>
              </div>

              <div className="flex items-center gap-3">
                <button className="btn-outline-gold px-4 py-2 text-sm font-medium flex items-center gap-2">
                  <Edit2 size={16} />
                  ویرایش
                </button>
                <button className="btn-gold px-4 py-2 text-sm font-bold flex items-center gap-2">
                  <Plus size={16} />
                  نوبت جدید
                </button>
              </div>
            </div>

            <div className="flex flex-wrap gap-4 text-sm">
              <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5">
                <CalendarDays size={14} className="text-[#C9A96E]" />
                <span className="text-[#A09880]">تاریخ عضویت:</span>
                <span className="text-[#F5F0E8]">{customer.joinDate}</span>
              </div>
              {customer.gender && (
                <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-white/5">
                  <span className="text-[#A09880]">جنسیت:</span>
                  <span className="text-[#F5F0E8]">{customer.gender}</span>
                </div>
              )}
              {historyCount > 0 && (
                <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-[#C9A96E]/10 border border-[#C9A96E]/20">
                  <BookOpen size={14} className="text-[#C9A96E]" />
                  <span className="text-[#C9A96E] text-xs font-medium">
                    {historyCount} یادداشت کارنامه
                  </span>
                </div>
              )}
            </div>

            {hasSensitivities && (
              <div className="mt-4 p-4 rounded-xl bg-[#E05555]/10 border border-[#E05555]/20 flex items-start gap-3">
                <AlertTriangle size={16} className="text-[#E05555] shrink-0 mt-0.5" />
                <div>
                  <p className="text-xs font-medium text-[#E05555] mb-1">
                    هشدار حساسیت (کارنامه زیبایی)
                  </p>
                  <p className="text-sm text-[#F5F0E8]/80">{beautyProfile.sensitivities}</p>
                </div>
              </div>
            )}

            {customer.notes && (
              <div className="mt-4 p-4 rounded-xl bg-white/5 border border-white/5">
                <div className="flex items-center gap-2 text-[#C9A96E] mb-2">
                  <StickyNote size={14} />
                  <span className="text-xs font-medium">یادداشت مدیر</span>
                </div>
                <p className="text-sm text-[#A09880]">{customer.notes}</p>
              </div>
            )}
          </div>
        </div>
      </motion.div>

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.1 }}
        className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden"
      >
        <div className="flex border-b border-[#2A2A3A]">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                "flex-1 py-4 text-sm font-medium transition-colors relative flex items-center justify-center gap-2",
                activeTab === tab.id
                  ? "text-[#C9A96E]"
                  : "text-[#A09880] hover:text-[#F5F0E8]"
              )}
            >
              {tab.label}
              {tab.badge !== undefined && tab.badge > 0 && (
                <span className="px-1.5 py-0.5 rounded-md bg-[#C9A96E]/20 text-[#C9A96E] text-xs font-bold min-w-[20px]">
                  {tab.badge}
                </span>
              )}
