/**
 * Review rating utilities
 */

import type { Review, StaffRatingSummary } from "@/lib/data/types";

export function getPublishedReviews(reviews: Review[]): Review[] {
  return reviews.filter((r) => r.status === "published");
}

export function computeStaffRating(
  staffId: string,
  reviews: Review[]
): StaffRatingSummary {
  const staffReviews = getPublishedReviews(reviews).filter(
    (r) => r.staffId === staffId
  );

  if (staffReviews.length === 0) {
    return { average: 0, count: 0 };
  }

  const sum = staffReviews.reduce((acc, r) => acc + r.rating, 0);
  return {
    average: Math.round((sum / staffReviews.length) * 10) / 10,
    count: staffReviews.length,
  };
}

export function computeStaffRatingsMap(
  reviews: Review[]
): Record<string, StaffRatingSummary> {
  const staffIds = [...new Set(reviews.map((r) => r.staffId))];
  return Object.fromEntries(
    staffIds.map((id) => [id, computeStaffRating(id, reviews)])
  );
}

export function formatRating(average: number): string {
  if (average === 0) return "—";
  return average.toLocaleString("fa-IR", {
    minimumFractionDigits: average % 1 === 0 ? 0 : 1,
    maximumFractionDigits: 1,
  });
}

export function ratingLabel(rating: number): string {
  const labels: Record<number, string> = {
    1: "ضعیف",
    2: "قابل قبول",
    3: "متوسط",
    4: "خوب",
    5: "عالی",
  };
  return labels[rating] ?? "";
}

import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { Review, ReviewStatus } from "@/lib/data/types";
import { mockReviews } from "@/lib/data/mock/reviews";
import {
  computeStaffRating,
  computeStaffRatingsMap,
  getPublishedReviews,
} from "@/lib/reviews/utils";

interface ReviewsState {
  initialized: boolean;
  reviews: Review[];
}

const initialState: ReviewsState = {
  initialized: false,
  reviews: [],
};

const reviewsSlice = createSlice({
  name: "reviews",
  initialState,
  reducers: {
    initializeReviews: (state) => {
      if (state.initialized) return;
      state.reviews = mockReviews.map((r) => ({ ...r }));
      state.initialized = true;
    },
    addReview: (
      state,
      action: PayloadAction<Omit<Review, "id" | "createdAt" | "status">>
    ) => {
      const review: Review = {
        ...action.payload,
        id: `rv_${Date.now()}`,
        status: "published",
        createdAt: new Date().toISOString(),
      };
      state.reviews.unshift(review);
    },
    updateReviewStatus: (
      state,
      action: PayloadAction<{ id: string; status: ReviewStatus }>
    ) => {
      const review = state.reviews.find((r) => r.id === action.payload.id);
      if (review) review.status = action.payload.status;
    },
    removeReview: (state, action: PayloadAction<string>) => {
      state.reviews = state.reviews.filter((r) => r.id !== action.payload);
    },
  },
});

export const { initializeReviews, addReview, updateReviewStatus, removeReview } =
  reviewsSlice.actions;

export const selectReviewsInitialized = (state: { reviews: ReviewsState }) =>
  state.reviews.initialized;

export const selectAllReviews = (state: { reviews: ReviewsState }) =>
  state.reviews.reviews;

export const selectPublishedReviews = (state: { reviews: ReviewsState }) =>
  getPublishedReviews(state.reviews.reviews);

export const selectReviewByAppointmentId =
  (appointmentId: string) => (state: { reviews: ReviewsState }) =>
    state.reviews.reviews.find((r) => r.appointmentId === appointmentId) ?? null;

export const selectReviewsByStaffId =
  (staffId: string) => (state: { reviews: ReviewsState }) =>
    state.reviews.reviews
      .filter((r) => r.staffId === staffId)
      .sort((a, b) => b.createdAt.localeCompare(a.createdAt));

export const selectReviewsByCustomerId =
  (customerId: string) => (state: { reviews: ReviewsState }) =>
    state.reviews.reviews
      .filter((r) => r.customerId === customerId)
      .sort((a, b) => b.createdAt.localeCompare(a.createdAt));

export const selectStaffRatingsMap = (state: { reviews: ReviewsState }) =>
  computeStaffRatingsMap(state.reviews.reviews);

export const selectStaffRating =
  (staffId: string) => (state: { reviews: ReviewsState }) =>
    computeStaffRating(staffId, state.reviews.reviews);

export const selectReviewStats = (state: { reviews: ReviewsState }) => {
  const published = getPublishedReviews(state.reviews.reviews);
  const total = published.length;
  const average =
    total === 0
      ? 0
      : Math.round(
          (published.reduce((sum, r) => sum + r.rating, 0) / total) * 10
        ) / 10;
  const fiveStar = published.filter((r) => r.rating === 5).length;
  const hidden = state.reviews.reviews.filter((r) => r.status === "hidden").length;

  return { total, average, fiveStar, hidden };
};

export default reviewsSlice.reducer;

