"use client";

import { Star } from "lucide-react";
import { cn } from "@/lib/cn";

interface StarRatingProps {
  value: number;
  max?: number;
  size?: "sm" | "md" | "lg";
  mode?: "display" | "input";
  onChange?: (value: number) => void;
  showValue?: boolean;
  className?: string;
}

const sizeMap = {
  sm: 14,
  md: 18,
  lg: 22,
};

export default function StarRating({
  value,
  max = 5,
  size = "md",
  mode = "display",
  onChange,
  showValue = false,
  className,
}: StarRatingProps) {
  const iconSize = sizeMap[size];
  const isInteractive = mode === "input" && !!onChange;

  return (
    <div className={cn("flex items-center gap-1", className)}>
      <div className="flex items-center gap-0.5" dir="ltr">
        {Array.from({ length: max }, (_, i) => {
          const starValue = i + 1;
          const filled = starValue <= Math.round(value);

          return (
            <button
              key={starValue}
              type="button"
              disabled={!isInteractive}
              onClick={() => onChange?.(starValue)}
              className={cn(
                "transition-transform",
                isInteractive && "hover:scale-110 cursor-pointer",
                !isInteractive && "cursor-default"
              )}
              aria-label={`${starValue} ستاره`}
            >
              <Star
                size={iconSize}
                className={cn(
                  filled ? "text-[#C9A96E] fill-[#C9A96E]" : "text-[#A09880]/40",
                  mode === "input" && !filled && "hover:text-[#C9A96E]/60"
                )}
              />
            </button>
          );
        })}
      </div>
      {showValue && value > 0 && (
        <span className="text-sm font-medium text-[#F5F0E8] mr-1">
          {value.toLocaleString("fa-IR", { maximumFractionDigits: 1 })}
        </span>
      )}
    </div>
  );
}

/** Compact rating badge for cards */
export function RatingBadge({
  average,
  count,
  variant = "admin",
}: {
  average: number;
  count: number;
  variant?: "admin" | "customer";
}) {
  if (count === 0) return null;

  const isAdmin = variant === "admin";

  return (
    <div
      className={cn(
        "inline-flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs font-medium",
        isAdmin
          ? "bg-[#C9A96E]/10 text-[#C9A96E]"
          : "bg-accent-bg text-accent"
      )}
    >
      <Star size={12} className="fill-current" />
      <span>{average.toLocaleString("fa-IR", { maximumFractionDigits: 1 })}</span>
      <span className={cn("opacity-70", isAdmin ? "text-[#A09880]" : "text-text-secondary")}>
        ({count.toLocaleString("fa-IR")})
      </span>
    </div>
  );
}

