export interface ReviewSubmitData {
  appointmentId: string;
  customerId: string;
  customerName: string;
  staffId: string;
  staffName: string;
  serviceId: string;
  serviceName: string;
  rating: number;
  comment: string;
}

interface ReviewModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: ReviewSubmitData) => void;
  appointment: {
    id: string;
    serviceName: string;
    staffName: string;
    staffId: string;
    serviceId: string;
    date: string;
  };
  customerId: string;
  customerName: string;
  isLoading?: boolean;
}

export default function ReviewModal({
  isOpen,
  onClose,
  onSubmit,
  appointment,
  customerId,
  customerName,
  isLoading = false,
}: ReviewModalProps) {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    if (isOpen) {
      setRating(0);
      setComment("");
      setError("");
    }
  }, [isOpen, appointment.id]);

  const handleSubmit = () => {
    if (rating === 0) {
      setError("لطفاً امتیاز خود را انتخاب کنید");
      return;
    }

    onSubmit({
      appointmentId: appointment.id,
      customerId,
      customerName,
      staffId: appointment.staffId,
      staffName: appointment.staffName,
      serviceId: appointment.serviceId,
      serviceName: appointment.serviceName,
      rating,
      comment: comment.trim(),
    });
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4"
        >
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ duration: 0.2 }}
            className="w-full max-w-md bg-bg-card border border-border rounded-2xl overflow-hidden"
          >
            <div className="flex items-center justify-between p-6 border-b border-border">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-accent/20 to-accent/5 flex items-center justify-center">
                  <Star size={20} className="text-accent" />
                </div>
                <div>
                  <h2 className="text-lg font-bold text-text-primary">ثبت نظر و امتیاز</h2>
                  <p className="text-xs text-text-secondary">{appointment.serviceName}</p>
                </div>
              </div>
              <button
                onClick={onClose}
                className="w-8 h-8 rounded-lg bg-bg-elevated flex items-center justify-center text-text-secondary hover:text-text-primary transition-colors"
              >
                <X size={18} />
              </button>
            </div>

            <div className="p-6 space-y-5">
              <div className="p-4 rounded-xl bg-bg-elevated text-center">
                <p className="text-sm text-text-secondary mb-1">آرایشگر</p>
                <p className="font-bold text-text-primary">{appointment.staffName}</p>
                <p className="text-xs text-text-secondary mt-1">{appointment.date}</p>
              </div>

              <div className="text-center">
                <p className="text-sm font-medium text-text-secondary mb-3">
                  تجربه شما چطور بود؟
                </p>
                <StarRating
                  value={rating}
                  mode="input"
                  size="lg"
                  onChange={setRating}
                  className="justify-center"
                />
                {rating > 0 && (
                  <p className="mt-2 text-sm text-accent font-medium">{ratingLabel(rating)}</p>
                )}
                {error && <p className="mt-2 text-xs text-error">{error}</p>}
              </div>

              <div>
                <label className="flex items-center gap-2 text-sm font-medium text-text-secondary mb-2">
                  <MessageSquare size={14} />
                  نظر شما (اختیاری)
                </label>
                <textarea
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  placeholder="تجربه‌تان را با دیگران به اشتراک بگذارید..."
                  rows={3}
                  className="w-full px-4 py-3 rounded-xl bg-bg-elevated border border-border text-text-primary placeholder:text-text-secondary/50 focus:outline-none focus:border-accent/50 transition-colors resize-none"
                />
              </div>
            </div>

            <div className="flex items-center gap-3 p-6 border-t border-border">
              <button
                onClick={onClose}
                className="flex-1 px-4 py-3 rounded-xl text-text-secondary hover:text-text-primary hover:bg-bg-elevated transition-colors font-medium"
              >
                بعداً
              </button>
              <button
                onClick={handleSubmit}
                disabled={isLoading}
                className={cn(
                  "flex-1 btn-gold px-4 py-3 font-bold flex items-center justify-center gap-2 disabled:opacity-50"
                )}
              >
                {isLoading ? <LoadingSpinner size={20} /> : "ثبت نظر"}
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

