"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Search, Star, MessageSquare, EyeOff } from "lucide-react";
import ReviewTable from "@/components/admin/ReviewTable";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  removeReview,
  selectAllReviews,
  selectReviewStats,
  updateReviewStatus,
} from "@/store/slices/reviewsSlice";
import { selectAdminStaff } from "@/store/slices/adminSlice";

const PAGE_SIZE = 6;

export default function ReviewsPage() {
  const dispatch = useAppDispatch();
  const reviews = useAppSelector(selectAllReviews);
  const stats = useAppSelector(selectReviewStats);
  const staffList = useAppSelector(selectAdminStaff);

  const [searchQuery, setSearchQuery] = useState("");
  const [staffFilter, setStaffFilter] = useState("");
  const [ratingFilter, setRatingFilter] = useState("");
  const [currentPage, setCurrentPage] = useState(1);

  const filteredReviews = useMemo(() => {
    return reviews.filter((r) => {
      const matchesSearch =
        r.customerName.includes(searchQuery) ||
        r.comment.includes(searchQuery) ||
        r.staffName.includes(searchQuery);
      const matchesStaff = !staffFilter || r.staffId === staffFilter;
      const matchesRating = !ratingFilter || r.rating === Number(ratingFilter);
      return matchesSearch && matchesStaff && matchesRating;
    });
  }, [reviews, searchQuery, staffFilter, ratingFilter]);

  const totalPages = Math.max(1, Math.ceil(filteredReviews.length / PAGE_SIZE));
  const paginatedReviews = filteredReviews.slice(
    (currentPage - 1) * PAGE_SIZE,
    currentPage * PAGE_SIZE
  );

  const handleToggleStatus = (id: string) => {
    const review = reviews.find((r) => r.id === id);
    if (!review) return;
    dispatch(
      updateReviewStatus({
        id,
        status: review.status === "published" ? "hidden" : "published",
      })
    );
  };

  const handleDelete = (id: string) => {
    if (window.confirm("آیا از حذف این نظر مطمئن هستید؟")) {
      dispatch(removeReview(id));
    }
  };

  const statCards = [
    {
      label: "میانگین امتیاز",
      value: stats.average > 0 ? stats.average.toLocaleString("fa-IR") : "—",
      icon: Star,
      color: "text-[#C9A96E]",
      bg: "bg-[#C9A96E]/10",
    },
    {
      label: "کل نظرات",
      value: stats.total.toLocaleString("fa-IR"),
      icon: MessageSquare,
      color: "text-[#3B82F6]",
      bg: "bg-[#3B82F6]/10",
    },
    {
      label: "۵ ستاره",
      value: stats.fiveStar.toLocaleString("fa-IR"),
      icon: Star,
      color: "text-[#4CAF82]",
      bg: "bg-[#4CAF82]/10",
    },
    {
      label: "مخفی‌شده",
      value: stats.hidden.toLocaleString("fa-IR"),
      icon: EyeOff,
      color: "text-[#A09880]",
      bg: "bg-[#A09880]/10",
    },
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((card, i) => (
          <motion.div
            key={card.label}
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 p-5"
          >
            <div className="flex items-center gap-3 mb-3">
              <div
                className={`w-10 h-10 rounded-xl ${card.bg} flex items-center justify-center`}
              >
                <card.icon size={18} className={card.color} />
              </div>
              <span className="text-sm text-[#A09880]">{card.label}</span>
            </div>
            <p className="text-2xl font-bold text-[#F5F0E8]">{card.value}</p>
          </motion.div>
        ))}
      </div>

      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col lg:flex-row items-stretch lg:items-center gap-4"
      >
        <div className="relative flex-1">
          <Search
            size={18}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-[#A09880]"
          />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => {
              setSearchQuery(e.target.value);
              setCurrentPage(1);
            }}
            placeholder="جستجو در نظرات..."
            className="w-full h-11 pr-12 pl-4 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none focus:border-[#C9A96E]/50 transition-colors"
          />
        </div>

        <select
          value={staffFilter}
          onChange={(e) => {
            setStaffFilter(e.target.value);
            setCurrentPage(1);
          }}
          className="h-11 px-4 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] focus:outline-none focus:border-[#C9A96E]/50 transition-colors appearance-none min-w-[160px]"
        >
          <option value="" className="bg-[#12121A]">
            همه آرایشگرها
          </option>
          {staffList.map((s) => (
            <option key={s.id} value={s.id} className="bg-[#12121A]">
              {s.name}
            </option>
          ))}
        </select>

        <select
          value={ratingFilter}
          onChange={(e) => {
            setRatingFilter(e.target.value);
            setCurrentPage(1);
          }}
          className="h-11 px-4 rounded-xl bg-white/5 border border-white/10 text-[#F5F0E8] focus:outline-none focus:border-[#C9A96E]/50 transition-colors appearance-none min-w-[140px]"
        >
          <option value="" className="bg-[#12121A]">
            همه امتیازها
          </option>
          {[5, 4, 3, 2, 1].map((n) => (
            <option key={n} value={n} className="bg-[#12121A]">
              {n} ستاره
            </option>
          ))}
        </select>
      </motion.div>

      <ReviewTable
        reviews={paginatedReviews}
        currentPage={currentPage}
        totalPages={totalPages}
        onPageChange={setCurrentPage}
        onToggleStatus={handleToggleStatus}
        onDelete={handleDelete}
      />
    </div>
  );
}

