}

export default function ProfilePage() {
  const dispatch = useAppDispatch();
  const authUser = useAppSelector(selectCurrentUser);
  const user = authUser
    ? {
        id: authUser.id === "u1" ? "c1" : authUser.id,
        name: authUser.name,
        phone: authUser.phone,
      }
    : mockUser;

  const [activeTab, setActiveTab] = useState<Tab>("upcoming");
  const [upcomingAppointments, setUpcomingAppointments] = useState(mockUpcomingAppointments);
  const [cancelDialogId, setCancelDialogId] = useState<string | null>(null);
  const [reviewAppointmentId, setReviewAppointmentId] = useState<string | null>(null);
  const [isSubmittingReview, setIsSubmittingReview] = useState(false);

  const handleNameUpdate = (newName: string) => {
    if (authUser) {
      dispatch(updateUserName(newName));
    }
  };

  const handleCancelAppointment = (id: string) => {
    setCancelDialogId(id);
  };

  const confirmCancel = () => {
    if (cancelDialogId) {
      setUpcomingAppointments((prev) => prev.filter((a) => a.id !== cancelDialogId));
      setCancelDialogId(null);
    }
  };

  const reviewAppointment = [...mockPastAppointments, ...upcomingAppointments].find(
    (a) => a.id === reviewAppointmentId
  );

  const handleSubmitReview = async (data: Parameters<typeof addReview>[0] extends infer A ? never : never) => {
    setIsSubmittingReview(true);
    await new Promise((r) => setTimeout(r, 500));
    dispatch(addReview(data));
    setIsSubmittingReview(false);
    setReviewAppointmentId(null);
  };

  const appointments =
    activeTab === "upcoming" ? upcomingAppointments : mockPastAppointments;

  return (
    <div className="min-h-screen bg-bg-primary">
      <header className="border-b border-border bg-bg-primary/80 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <Logo size="sm" />
          <div className="flex items-center gap-3">
            <ThemeToggle />
            <Link
              href="/"
              className="flex items-center gap-2 text-sm text-text-secondary hover:text-accent transition-colors"
            >
              بازگشت
              <ArrowRight size={16} />
            </Link>
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-4 py-8 space-y-8">
        <ProfileCard name={user.name} phone={user.phone} onNameUpdate={handleNameUpdate} />

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="rounded-2xl bg-glass-bg backdrop-blur-md border border-glass-border overflow-hidden"
        >
          <div className="flex border-b border-border">
            <button
              onClick={() => setActiveTab("upcoming")}
              className={cn(
                "flex-1 py-4 text-sm font-medium transition-colors relative",
                activeTab === "upcoming" ? "text-accent" : "text-text-secondary hover:text-text-primary"
              )}
            >
              نوبت‌های پیش رو
              {upcomingAppointments.length > 0 && (
                <span className="mr-2 px-2 py-0.5 rounded-full bg-accent-bg text-[10px] text-accent">
                  {upcomingAppointments.length}
                </span>
              )}
              {activeTab === "upcoming" && (
                <motion.div layoutId="profileTab" className="absolute bottom-0 right-0 left-0 h-0.5 bg-accent" />
              )}
            </button>
            <button
              onClick={() => setActiveTab("history")}
              className={cn(
                "flex-1 py-4 text-sm font-medium transition-colors relative",
                activeTab === "history" ? "text-accent" : "text-text-secondary hover:text-text-primary"
              )}
            >
              تاریخچه
              {activeTab === "history" && (
                <motion.div layoutId="profileTab" className="absolute bottom-0 right-0 left-0 h-0.5 bg-accent" />
              )}
            </button>
          </div>

          <div className="p-4">
            <AnimatePresence mode="wait">
              {appointments.length === 0 ? (
                <motion.div
                  key="empty"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="py-12 text-center"
                >
                  <CalendarX size={48} className="mx-auto text-text-secondary mb-4" />
                  <h3 className="text-lg font-bold text-text-primary mb-2">
                    {activeTab === "upcoming" ? "نوبت آینده‌ای ندارید" : "تاریخچه‌ای وجود ندارد"}
                  </h3>
                  <p className="text-sm text-text-secondary mb-6">
                    {activeTab === "upcoming"
                      ? "همین الان اولین نوبتتان را رزرو کنید"
                      : "هنوز نوبتی نگرفته‌اید"}
                  </p>
                  {activeTab === "upcoming" && (
                    <Link
                      href="/book"
                      className="inline-flex items-center gap-2 btn-gold px-6 py-2.5 text-sm font-bold"
                    >
                      <Plus size={16} />
                      رزرو نوبت
                    </Link>
                  )}
                </motion.div>
              ) : (
                <motion.div
                  key="list"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="space-y-4"
                >
                  {appointments.map((apt, i) => (
                    <AppointmentWithReview
                      key={apt.id}
                      appointment={apt}
                      showCancelButton={activeTab === "upcoming"}
                      showReviewButton={activeTab === "history"}
                      onCancel={handleCancelAppointment}
                      onReview={setReviewAppointmentId}
                      delay={i * 0.05}
                    />
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </motion.div>

        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}>
          <Link
            href="/book"
            className="w-full btn-gold py-4 font-bold flex items-center justify-center gap-2 rounded-2xl"
          >
            <Plus size={20} />
            رزرو نوبت جدید
          </Link>
        </motion.div>
      </main>

      {reviewAppointment && (
        <ReviewModal
          isOpen={!!reviewAppointmentId}
          onClose={() => setReviewAppointmentId(null)}
          onSubmit={(data) => {
            setIsSubmittingReview(true);
            dispatch(addReview(data));
            setTimeout(() => {
              setIsSubmittingReview(false);
              setReviewAppointmentId(null);
            }, 400);
          }}
          appointment={reviewAppointment}
          customerId={user.id}
          customerName={user.name}
          isLoading={isSubmittingReview}
        />
      )}

      <AnimatePresence>
        {cancelDialogId && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4"
          >
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="w-full max-w-sm bg-bg-card border border-border rounded-2xl p-6 text-center"
            >
              <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-error-bg flex items-center justify-center">
                <AlertTriangle size={32} className="text-error" />
              </div>
              <h3 className="text-xl font-bold text-text-primary mb-2">لغو نوبت</h3>
              <p className="text-text-secondary mb-6">
                آیا از لغو این نوبت اطمینان دارید؟ این عمل قابل بازگشت نیست.
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setCancelDialogId(null)}
                  className="flex-1 px-4 py-3 rounded-xl text-text-secondary hover:text-text-primary hover:bg-bg-elevated transition-colors font-medium"
                >
                  انصراف
                </button>
                <button
                  onClick={confirmCancel}
                  className="flex-1 px-4 py-3 rounded-xl bg-error text-white font-bold hover:bg-error/90 transition-colors"
                >
                  بله، لغو کن
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

