import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { PortfolioItem } from "@/lib/data/types";
import { mockPortfolio } from "@/lib/data/mock/portfolio";

interface GalleryState {
  initialized: boolean;
  items: PortfolioItem[];
}

const initialState: GalleryState = {
  initialized: false,
  items: [],
};

const gallerySlice = createSlice({
  name: "gallery",
  initialState,
  reducers: {
    initializeGallery: (state) => {
      if (state.initialized) return;
      state.items = mockPortfolio.map((item) => ({ ...item }));
      state.initialized = true;
    },
    upsertPortfolioItem: (state, action: PayloadAction<PortfolioItem>) => {
      const index = state.items.findIndex((i) => i.id === action.payload.id);
      if (index >= 0) {
        state.items[index] = action.payload;
      } else {
        state.items.unshift(action.payload);
      }
    },
    removePortfolioItem: (state, action: PayloadAction<string>) => {
      state.items = state.items.filter((i) => i.id !== action.payload);
    },
    togglePortfolioFeatured: (state, action: PayloadAction<string>) => {
      const item = state.items.find((i) => i.id === action.payload);
      if (item) item.isFeatured = !item.isFeatured;
    },
    togglePortfolioPublished: (state, action: PayloadAction<string>) => {
      const item = state.items.find((i) => i.id === action.payload);
      if (item) item.isPublished = !item.isPublished;
    },
    incrementPortfolioLikes: (state, action: PayloadAction<string>) => {
      const item = state.items.find((i) => i.id === action.payload);
      if (item) item.likes += 1;
    },
  },
});

export const {
  initializeGallery,
  upsertPortfolioItem,
  removePortfolioItem,
  togglePortfolioFeatured,
  togglePortfolioPublished,
  incrementPortfolioLikes,
} = gallerySlice.actions;

export const selectGalleryInitialized = (state: { gallery: GalleryState }) =>
  state.gallery.initialized;

export const selectAllPortfolioItems = (state: { gallery: GalleryState }) =>
  state.gallery.items;

export const selectPublishedPortfolio = (state: { gallery: GalleryState }) =>
  state.gallery.items.filter((i) => i.isPublished);

export const selectFeaturedPortfolio = (state: { gallery: GalleryState }) =>
  state.gallery.items.filter((i) => i.isPublished && i.isFeatured);

export const selectPortfolioByStaffId =
  (staffId: string) => (state: { gallery: GalleryState }) =>
    state.gallery.items.filter((i) => i.isPublished && i.staffId === staffId);

export const selectPortfolioById =
  (id: string) => (state: { gallery: GalleryState }) =>
    state.gallery.items.find((i) => i.id === id) ?? null;

export default gallerySlice.reducer;

