interface PortfolioGridProps {
  items: PortfolioItem[];
  onItemClick: (item: PortfolioItem) => void;
  onLike?: (id: string) => void;
  variant?: "landing" | "gallery";
  showFilters?: boolean;
  initialStaffFilter?: string;
}

export function PortfolioGrid({
  items,
  onItemClick,
  onLike,
  variant = "gallery",
  showFilters = true,
  initialStaffFilter = "",
}: PortfolioGridProps) {
  const [categoryFilter, setCategoryFilter] = useState<PortfolioCategory | "all">("all");

  const filteredItems = useMemo(() => {
    return items.filter((item) => {
      const matchCategory = categoryFilter === "all" || item.category === categoryFilter;
      const matchStaff = !initialStaffFilter || item.staffId === initialStaffFilter;
      return matchCategory && matchStaff;
    });
  }, [items, categoryFilter, initialStaffFilter]);

  const categories: (PortfolioCategory | "all")[] = [
    "all",
    "color",
    "haircut",
    "keratin",
    "brushing",
    "other",
  ];

  return (
    <div className="space-y-6">
      {showFilters && (
        <div className="flex flex-wrap gap-2">
          {categories.map((cat) => (
            <button
              key={cat}
              type="button"
              onClick={() => setCategoryFilter(cat)}
              className={cn(
                "px-4 py-2 rounded-xl text-sm font-medium transition-all duration-300",
                categoryFilter === cat
                  ? "bg-accent text-bg-primary"
                  : "bg-glass-bg border border-glass-border text-text-secondary hover:text-text-primary hover:border-accent/30"
              )}
            >
              {cat === "all" ? "همه" : portfolioCategoryLabels[cat]}
            </button>
          ))}
        </div>
      )}

      {filteredItems.length === 0 ? (
        <div className="py-16 text-center text-text-secondary">
          نمونه‌کاری در این دسته یافت نشد.
        </div>
      ) : (
        <div
          className={cn(
            "grid gap-4 sm:gap-6",
            variant === "landing"
              ? "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3"
              : "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4"
          )}
        >
          {filteredItems.map((item, i) => (
            <PortfolioCard
              key={item.id}
              item={item}
              variant={variant}
              delay={i * 0.06}
              onClick={() => onItemClick(item)}
              onLike={() => onLike?.(item.id)}
            />
          ))}
        </div>
      )}
    </div>
  );
}

