"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Images } from "lucide-react";
import LoadingSpinner from "@/components/shared/LoadingSpinner";
import type { PortfolioItem, PortfolioCategory, Staff, Service } from "@/lib/data/types";
import { portfolioCategoryLabels } from "@/lib/data/mock/portfolio";

interface PortfolioModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: PortfolioItem) => void;
  initialData?: PortfolioItem | null;
  staffList: Staff[];
  serviceList: Service[];
  isLoading?: boolean;
}

const emptyItem = (): Omit<PortfolioItem, "id" | "createdAt"> => ({
  title: "",
  description: "",
  staffId: "",
  staffName: "",
  serviceId: "",
  serviceName: "",
  category: "other",
  beforeImageUrl: "",
  afterImageUrl: "",
  tags: [],
  likes: 0,
  isFeatured: false,
  isPublished: true,
});

export default function PortfolioModal({
  isOpen,
  onClose,
  onSave,
  initialData,
  staffList,
  serviceList,
  isLoading = false,
}: PortfolioModalProps) {
  const [form, setForm] = useState(emptyItem());
  const [tagsInput, setTagsInput] = useState("");
  const [errors, setErrors] = useState<Record<string, string>>({});

  const isEditing = !!initialData?.id;

  useEffect(() => {
    if (initialData) {
      setForm({
        title: initialData.title,
        description: initialData.description,
        staffId: initialData.staffId,
        staffName: initialData.staffName,
        serviceId: initialData.serviceId,
        serviceName: initialData.serviceName,
        category: initialData.category,
        beforeImageUrl: initialData.beforeImageUrl,
        afterImageUrl: initialData.afterImageUrl,
        tags: initialData.tags,
        likes: initialData.likes,
        isFeatured: initialData.isFeatured,
        isPublished: initialData.isPublished,
      });
      setTagsInput(initialData.tags.join("، "));
    } else {
      setForm(emptyItem());
      setTagsInput("");
    }
    setErrors({});
  }, [initialData, isOpen]);

  const validate = () => {
    const next: Record<string, string> = {};
    if (!form.title.trim()) next.title = "عنوان الزامی است";
    if (!form.staffId) next.staffId = "آرایشگر الزامی است";
    if (!form.beforeImageUrl.trim()) next.beforeImageUrl = "تصویر قبل الزامی است";
    if (!form.afterImageUrl.trim()) next.afterImageUrl = "تصویر بعد الزامی است";
    setErrors(next);
    return Object.keys(next).length === 0;
  };

  const handleSubmit = () => {
    if (!validate()) return;

    const staff = staffList.find((s) => s.id === form.staffId);
    const service = serviceList.find((s) => s.id === form.serviceId);
    const tags = tagsInput
      .split(/[،,]/)
      .map((t) => t.trim())
      .filter(Boolean);

    onSave({
      ...form,
      id: initialData?.id ?? `pf_${Date.now()}`,
      staffName: staff?.name ?? form.staffName,
      serviceName: service?.name ?? form.serviceName,
      serviceId: service?.id ?? form.serviceId,
      category: (service?.category as PortfolioCategory) ?? form.category,
      tags,
      createdAt: initialData?.createdAt ?? new Date().toISOString(),
    });
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm px-4 py-6 overflow-y-auto"
        >
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="w-full max-w-lg bg-[#12121A] border border-white/10 rounded-2xl overflow-hidden my-auto"
          >
            <div className="flex items-center justify-between p-6 border-b border-[#2A2A3A]">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5 flex items-center justify-center">
                  <Images size={20} className="text-[#C9A96E]" />
                </div>
                <h2 className="text-lg font-bold text-[#F5F0E8]">
                  {isEditing ? "ویرایش نمونه‌کار" : "نمونه‌کار جدید"}
                </h2>
              </div>
              <button
                onClick={onClose}
                className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-[#A09880] hover:text-[#F5F0E8]"
              >
                <X size={18} />
              </button>
            </div>

            <div className="p-6 space-y-4 max-h-[65vh] overflow-y-auto">
              <Field label="عنوان" required error={errors.title}>
                <input
                  value={form.title}
                  onChange={(e) => setForm((p) => ({ ...p, title: e.target.value }))}
                  className={inputClass(!!errors.title)}
                  placeholder="مثال: بلوند دودی با هایلایت"
                />
              </Field>

              <Field label="توضیحات">
                <textarea
                  value={form.description}
                  onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))}
                  rows={2}
                  className={inputClass()}
                  placeholder="توضیح کوتاه درباره کار انجام‌شده..."
                />
              </Field>

              <div className="grid grid-cols-2 gap-4">
                <Field label="آرایشگر" required error={errors.staffId}>
                  <select
                    value={form.staffId}
                    onChange={(e) => setForm((p) => ({ ...p, staffId: e.target.value }))}
                    className={inputClass(!!errors.staffId)}
                  >
                    <option value="" className="bg-[#12121A]">
                      انتخاب
                    </option>
                    {staffList.filter((s) => s.isActive).map((s) => (
                      <option key={s.id} value={s.id} className="bg-[#12121A]">
                        {s.name}
                      </option>
                    ))}
                  </select>
                </Field>

                <Field label="سرویس">
                  <select
                    value={form.serviceId}
                    onChange={(e) => setForm((p) => ({ ...p, serviceId: e.target.value }))}
                    className={inputClass()}
                  >
                    <option value="" className="bg-[#12121A]">
                      انتخاب
                    </option>
                    {serviceList.filter((s) => s.isActive).map((s) => (
                      <option key={s.id} value={s.id} className="bg-[#12121A]">
                        {s.name}
                      </option>
                    ))}
                  </select>
                </Field>
              </div>

              <Field label="دسته‌بندی">
                <select
                  value={form.category}
                  onChange={(e) =>
                    setForm((p) => ({ ...p, category: e.target.value as PortfolioCategory }))
                  }
                  className={inputClass()}
                >
                  {Object.entries(portfolioCategoryLabels).map(([key, label]) => (
                    <option key={key} value={key} className="bg-[#12121A]">
                      {label}
                    </option>
                  ))}
                </select>
              </Field>

              <Field label="آدرس تصویر قبل" required error={errors.beforeImageUrl}>
                <input
                  value={form.beforeImageUrl}
                  onChange={(e) => setForm((p) => ({ ...p, beforeImageUrl: e.target.value }))}
                  dir="ltr"
                  className={inputClass(!!errors.beforeImageUrl)}
                  placeholder="https://..."
                />
              </Field>

              <Field label="آدرس تصویر بعد" required error={errors.afterImageUrl}>
                <input
                  value={form.afterImageUrl}
                  onChange={(e) => setForm((p) => ({ ...p, afterImageUrl: e.target.value }))}
                  dir="ltr"
                  className={inputClass(!!errors.afterImageUrl)}
                  placeholder="https://..."
                />
              </Field>

              <Field label="برچسب‌ها (با ، جدا کنید)">
                <input
                  value={tagsInput}
                  onChange={(e) => setTagsInput(e.target.value)}
                  className={inputClass()}
                  placeholder="بلوند، هایلایت"
                />
              </Field>

              <div className="flex flex-wrap gap-4 pt-2">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={form.isFeatured}
                    onChange={(e) => setForm((p) => ({ ...p, isFeatured: e.target.checked }))}
                    className="rounded border-white/20"
                  />
                  <span className="text-sm text-[#A09880]">ویژه (صفحه اصلی)</span>
                </label>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={form.isPublished}
                    onChange={(e) => setForm((p) => ({ ...p, isPublished: e.target.checked }))}
                    className="rounded border-white/20"
                  />
                  <span className="text-sm text-[#A09880]">منتشر شده</span>
                </label>
              </div>
            </div>

            <div className="flex gap-3 p-6 border-t border-[#2A2A3A]">
              <button
                onClick={onClose}
                className="flex-1 py-3 rounded-xl text-[#A09880] hover:bg-white/5 font-medium"
              >
                انصراف
              </button>
              <button
                onClick={handleSubmit}
                disabled={isLoading}
                className="flex-1 btn-gold py-3 font-bold flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isLoading ? <LoadingSpinner size={20} /> : "ذخیره"}
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

function inputClass(error?: boolean) {
  return `w-full px-4 py-3 rounded-xl bg-white/5 border text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:outline-none transition-colors ${
    error ? "border-[#E05555]/50" : "border-white/10 focus:border-[#C9A96E]/50"
  }`;
}

function Field({
  label,
  required,
  error,
  children,
}: {
  label: string;
  required?: boolean;
  error?: string;
  children: React.ReactNode;
}) {
  return (
    <div>
      <label className="block text-sm font-medium text-[#A09880] mb-2">
        {label}
        {required && <span className="text-[#E05555] mr-1">*</span>}
      </label>
      {children}
      {error && <p className="mt-1 text-xs text-[#E05555]">{error}</p>}
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Plus, Images, Star, Eye, EyeOff, Trash2, Edit2 } from "lucide-react";
import { cn } from "@/lib/cn";
