import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  removePortfolioItem,
  selectAllPortfolioItems,
  togglePortfolioFeatured,
  togglePortfolioPublished,
  upsertPortfolioItem,
} from "@/store/slices/gallerySlice";
import { selectAdminStaff, selectAdminServices } from "@/store/slices/adminSlice";

export default function GalleryAdminPage() {
  const dispatch = useAppDispatch();
  const items = useAppSelector(selectAllPortfolioItems);
  const staffList = useAppSelector(selectAdminStaff);
  const serviceList = useAppSelector(selectAdminServices);

  const [modalOpen, setModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<PortfolioItem | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const publishedCount = items.filter((i) => i.isPublished).length;
  const featuredCount = items.filter((i) => i.isFeatured && i.isPublished).length;

  const handleEdit = (item: PortfolioItem) => {
    setEditingItem(item);
    setModalOpen(true);
  };

  const handleSave = async (data: PortfolioItem) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 400));
    dispatch(upsertPortfolioItem(data));
    setIsLoading(false);
    setModalOpen(false);
    setEditingItem(null);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("آیا از حذف این نمونه‌کار مطمئن هستید؟")) {
      dispatch(removePortfolioItem(id));
    }
  };

  return (
    <div className="space-y-6">
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-4"
