          <span>·</span>
          <span>{publishedCount.toLocaleString("fa-IR")} منتشر شده</span>
          <span>·</span>
          <span>{featuredCount.toLocaleString("fa-IR")} ویژه</span>
        </div>
        <button
          onClick={() => {
            setEditingItem(null);
            setModalOpen(true);
          }}
          className="btn-gold px-6 py-2.5 font-bold flex items-center justify-center gap-2"
        >
          <Plus size={18} />
          نمونه‌کار جدید
        </button>
      </motion.div>

      {items.length === 0 ? (
        <div className="rounded-2xl bg-white/5 border border-white/10 p-16 text-center">
          <Images size={48} className="mx-auto text-[#A09880]/50 mb-4" />
          <p className="text-[#A09880]">هنوز نمونه‌کاری ثبت نشده است.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-5">
          {items.map((item, i) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.04 }}
              className="rounded-2xl bg-white/5 border border-white/10 overflow-hidden group"
            >
              <div className="p-3">
                <BeforeAfterSlider
                  beforeImageUrl={item.beforeImageUrl}
                  afterImageUrl={item.afterImageUrl}
                  className="rounded-xl aspect-[16/10] !aspect-auto h-44"
                  initialPosition={40}
                />
              </div>

              <div className="px-4 pb-4">
                <div className="flex items-start justify-between gap-2 mb-2">
                  <div className="min-w-0">
                    <h3 className="font-bold text-[#F5F0E8] truncate">{item.title}</h3>
                    <p className="text-xs text-[#A09880]">
                      {item.staffName} · {item.serviceName}
