                  </div>
                  <div className="flex flex-col gap-1 shrink-0">
                    {item.isFeatured && (
                      <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-md bg-[#C9A96E]/10 text-[#C9A96E] text-[10px] whitespace-nowrap">
                        <Star size={10} />
                        ویژه
                      </span>
                    )}
                    <span
                      className={cn(
                        "inline-flex px-2 py-0.5 rounded-md text-[10px] font-medium whitespace-nowrap",
                        item.isPublished
                          ? "bg-[#4CAF82]/10 text-[#4CAF82]"
                          : "bg-[#A09880]/10 text-[#A09880]"
                      )}
                    >
                      {item.isPublished ? "منتشر شده" : "پیش‌نویس"}
                    </span>
                  </div>
                </div>

                <div className="flex items-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity pt-2 border-t border-[#2A2A3A]/50">
                  <button
                    onClick={() => handleEdit(item)}
                    className="flex-1 flex items-center justify-center gap-1 py-2 rounded-lg bg-white/5 text-xs text-[#A09880] hover:text-[#C9A96E] hover:bg-[#C9A96E]/10"
                  >
                    <Edit2 size={12} />
                    ویرایش
                  </button>
                  <button
                    onClick={() => dispatch(togglePortfolioFeatured(item.id))}
                    title="ویژه"
                    className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-[#A09880] hover:text-[#C9A96E]"
                  >
                    <Star size={14} />
                  </button>
                  <button
                    onClick={() => dispatch(togglePortfolioPublished(item.id))}
