"use client";

import { useCallback, useRef, useState, type PointerEvent } from "react";
import { cn } from "@/lib/cn";
import { GripVertical, ImageOff } from "lucide-react";

interface BeforeAfterSliderProps {
  beforeImageUrl: string;
  afterImageUrl: string;
  beforeLabel?: string;
  afterLabel?: string;
  className?: string;
  initialPosition?: number;
}

function ImageLayer({
  src,
  alt,
  className,
  style,
  onError,
}: {
  src: string;
  alt: string;
  className?: string;
  style?: React.CSSProperties;
  onError: () => void;
}) {
  const [failed, setFailed] = useState(false);

  if (failed) {
    return (
      <div
        className={cn(
          "absolute inset-0 flex flex-col items-center justify-center bg-gradient-to-br from-bg-elevated to-bg-card text-text-secondary",
          className
        )}
        style={style}
      >
        <ImageOff size={28} className="mb-2 opacity-50" />
        <span className="text-xs">{alt}</span>
      </div>
    );
  }

  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src={src}
      alt={alt}
      className={className}
      style={style}
      draggable={false}
      loading="lazy"
      onError={() => {
        setFailed(true);
        onError();
      }}
    />
  );
}

export default function BeforeAfterSlider({
  beforeImageUrl,
  afterImageUrl,
  beforeLabel = "قبل",
  afterLabel = "بعد",
  className,
  initialPosition = 50,
}: BeforeAfterSliderProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState(initialPosition);
  const [isDragging, setIsDragging] = useState(false);

  const updatePosition = useCallback((clientX: number) => {
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const x = clientX - rect.left;
    const pct = Math.min(100, Math.max(0, (x / rect.width) * 100));
    setPosition(pct);
  }, []);

  const handlePointerDown = (e: PointerEvent) => {
    setIsDragging(true);
    containerRef.current?.setPointerCapture(e.pointerId);
    updatePosition(e.clientX);
  };

  const handlePointerMove = (e: PointerEvent) => {
    if (!isDragging) return;
    updatePosition(e.clientX);
  };

  const handlePointerUp = (e: PointerEvent) => {
    setIsDragging(false);
    try {
      containerRef.current?.releasePointerCapture(e.pointerId);
    } catch {
      /* already released */
    }
  };

  // clip-path: show left `position`% of the before image (full-size overlay)
  const beforeClip = `inset(0 ${100 - position}% 0 0)`;

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full overflow-hidden rounded-2xl select-none touch-none bg-bg-elevated aspect-[4/5]",
        className
      )}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerUp}
    >
      {/* After (base) */}
      <ImageLayer
        src={afterImageUrl}
        alt={afterLabel}
        className="absolute inset-0 h-full w-full object-cover pointer-events-none"
        onError={() => {}}
      />

      {/* Before (full-size, clipped — fixes partial/broken sizing) */}
      <ImageLayer
        src={beforeImageUrl}
        alt={beforeLabel}
        className="absolute inset-0 h-full w-full object-cover pointer-events-none z-[1]"
        style={{ clipPath: beforeClip }}
        onError={() => {}}
      />

      <span className="absolute top-3 right-3 px-2.5 py-1 rounded-lg bg-black/50 backdrop-blur-sm text-xs font-medium text-white z-10 pointer-events-none">
        {beforeLabel}
      </span>
      <span className="absolute top-3 left-3 px-2.5 py-1 rounded-lg bg-accent/90 text-xs font-bold text-bg-primary z-10 pointer-events-none">
        {afterLabel}
      </span>

      <div
        className="absolute inset-y-0 z-20 w-0.5 bg-white shadow-[0_0_12px_rgba(0,0,0,0.5)] pointer-events-none"
        style={{ left: `${position}%`, transform: "translateX(-50%)" }}
      >
        <div
          className={cn(
            "absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white shadow-lg flex items-center justify-center border-2 border-accent transition-transform pointer-events-none",
            isDragging && "scale-110"
          )}
        >
          <GripVertical size={18} className="text-accent" />
        </div>
      </div>
    </div>
  );
}

