/**
 * Smart dashboard analytics — revenue forecast, churn alerts, gap analysis
 */

import type {
  Appointment,
  AtRiskCustomer,
  ChurnRiskLevel,
  Customer,
  RevenueForecast,
  Staff,
  TimeGap,
} from "@/lib/data/types";

const PERSIAN_DIGITS = "۰۱۲۳۴۵۶۷۸۹";

export const ANALYTICS_WEEK_DATES = [
  "۱۴۰۳/۱۰/۱۵",
  "۱۴۰۳/۱۰/۱۶",
  "۱۴۰۳/۱۰/۱۷",
  "۱۴۰۳/۱۰/۱۸",
  "۱۴۰۳/۱۰/۱۹",
  "۱۴۰۳/۱۰/۲۰",
  "۱۴۰۳/۱۰/۲۱",
] as const;

const DAY_LABELS: Record<string, string> = {
  "۱۴۰۳/۱۰/۱۵": "شنبه",
  "۱۴۰۳/۱۰/۱۶": "یک‌شنبه",
  "۱۴۰۳/۱۰/۱۷": "دوشنبه",
  "۱۴۰۳/۱۰/۱۸": "سه‌شنبه",
  "۱۴۰۳/۱۰/۱۹": "چهارشنبه",
  "۱۴۰۳/۱۰/۲۰": "پنج‌شنبه",
  "۱۴۰۳/۱۰/۲۱": "جمعه",
};

function toAsciiDigits(str: string): string {
  return str.replace(/[۰-۹]/g, (c) => String(PERSIAN_DIGITS.indexOf(c)));
}

function toPersianDigits(n: number): string {
  return n.toString().replace(/\d/g, (d) => PERSIAN_DIGITS[parseInt(d, 10)]);
}

/** Approximate days between two Jalali-style dates (demo accuracy) */
export function daysBetweenPersian(from: string | null, to: string): number {
  if (!from) return 999;

  const fromParts = toAsciiDigits(from).split("/").map(Number);
  const toParts = toAsciiDigits(to).split("/").map(Number);

  const fromDays = fromParts[0] * 365 + fromParts[1] * 30 + fromParts[2];
  const toDays = toParts[0] * 365 + toParts[1] * 30 + toParts[2];

  return Math.max(0, toDays - fromDays);
}

function isInWeek(date: string, weekDates: readonly string[]): boolean {
  return weekDates.includes(date);
}

function countsTowardRevenue(status: Appointment["status"]): boolean {
  return status === "confirmed" || status === "completed" || status === "pending";
}

export function computeRevenueForecast(
  appointments: Appointment[],
  weekDates: readonly string[] = ANALYTICS_WEEK_DATES
): RevenueForecast {
  const weekAppointments = appointments.filter((a) => isInWeek(a.date, weekDates));

  let confirmedRevenue = 0;
  let pendingRevenue = 0;
  let confirmedCount = 0;
  let pendingCount = 0;
  let cancelledCount = 0;

  for (const apt of weekAppointments) {
    if (apt.status === "confirmed" || apt.status === "completed") {
      confirmedRevenue += apt.price;
      confirmedCount += 1;
    } else if (apt.status === "pending") {
      pendingRevenue += apt.price;
      pendingCount += 1;
    } else if (apt.status === "cancelled" || apt.status === "no_show") {
      cancelledCount += 1;
    }
  }

  const dailyBreakdown = weekDates.map((date) => ({
    date,
    dayLabel: DAY_LABELS[date] ?? date,
    amount: weekAppointments
      .filter(
        (a) =>
          a.date === date &&
          (a.status === "confirmed" || a.status === "completed" || a.status === "pending")
      )
      .reduce((sum, a) => sum + a.price, 0),
  }));

  return {
    weekLabel: "هفته ۱۵ تا ۲۱ دی ۱۴۰۳",
    confirmedRevenue,
    pendingRevenue,
    totalExpected: confirmedRevenue + pendingRevenue,
    confirmedCount,
    pendingCount,
    cancelledCount,
    dailyBreakdown,
  };
}

function getRiskLevel(daysSince: number, status: Customer["status"]): ChurnRiskLevel | null {
  if (status === "inactive") return "high";
  if (daysSince >= 25) return "high";
  if (daysSince >= 14) return "medium";
  if (daysSince >= 7) return "low";
  return null;
}

function getSuggestedAction(
  risk: ChurnRiskLevel,
  daysSince: number,
  appointmentsCount: number
): string {
  if (risk === "high") {
    return appointmentsCount > 0
      ? "ارسال پیامک تخفیف بازگشت — بیش از ۳ هفته غایب"
      : "تماس خوش‌آمدگویی — مشتری جدید بدون مراجعه";
  }
  if (risk === "medium") {
    return "یادآوری نوبت + پیشنهاد سرویس مکمل";
  }
  return `پیگیری ملایم — ${daysSince.toLocaleString("fa-IR")} روز از آخرین مراجعه`;
}

export function computeAtRiskCustomers(
  customers: Customer[],
  todayDate: string
): AtRiskCustomer[] {
  const atRisk: AtRiskCustomer[] = [];

  for (const customer of customers) {
    const daysSince = daysBetweenPersian(customer.lastAppointment, todayDate);
    const riskLevel = getRiskLevel(daysSince, customer.status);
    if (!riskLevel) continue;

    atRisk.push({
      customerId: customer.id,
      customerName: customer.name,
      phone: customer.phone,
      lastAppointment: customer.lastAppointment,
      daysSinceVisit: daysSince,
      appointmentsCount: customer.appointmentsCount,
      riskLevel,
      suggestedAction: getSuggestedAction(
        riskLevel,
        daysSince,
        customer.appointmentsCount
      ),
    });
  }

  const order: Record<ChurnRiskLevel, number> = { high: 0, medium: 1, low: 2 };
  return atRisk.sort(
    (a, b) =>
      order[a.riskLevel] - order[b.riskLevel] || b.daysSinceVisit - a.daysSinceVisit
  );
}

function generateTimeSlots(): string[] {
  const slots: string[] = [];
  for (let hour = 9; hour <= 17; hour++) {
    for (const min of [0, 30]) {
      if (hour === 17 && min === 30) continue;
      slots.push(`${toPersianDigits(hour)}:${min === 0 ? "۰۰" : "۳۰"}`);
    }
  }
  return slots;
}

const ALL_SLOTS = generateTimeSlots();

export function computeGapAnalysis(
  appointments: Appointment[],
  staff: Staff[],
  weekDates: readonly string[] = ANALYTICS_WEEK_DATES,
  maxGaps = 12
): TimeGap[] {
  const activeStaff = staff.filter((s) => s.isActive);
  const gaps: TimeGap[] = [];

  for (const date of weekDates) {
    for (const member of activeStaff) {
      const bookedTimes = new Set(
        appointments
          .filter(
            (a) =>
              a.date === date &&
              a.staffId === member.id &&
              a.status !== "cancelled"
          )
          .map((a) => a.time)
      );

      for (const time of ALL_SLOTS) {
        if (!bookedTimes.has(time)) {
          gaps.push({
            id: `gap_${date}_${member.id}_${time}`,
            date,
            dayLabel: DAY_LABELS[date] ?? date,
            time,
            staffId: member.id,
            staffName: member.name,
            durationMinutes: 30,
          });
        }
      }
    }
  }

  // Prioritize near-term days and morning prime slots
  const dateOrder = new Map(weekDates.map((d, i) => [d, i]));
  return gaps
    .sort((a, b) => {
      const dateDiff =
        (dateOrder.get(a.date) ?? 0) - (dateOrder.get(b.date) ?? 0);
      if (dateDiff !== 0) return dateDiff;
      return a.time.localeCompare(b.time, "fa");
    })
    .slice(0, maxGaps);
}

