/**
 * Staff profile helpers — dedicated booking pages (/book/[slug])
 */

import { mockStaff } from "@/lib/data/mock/staff";
import type { Staff } from "@/lib/data/types";

export function getStaffProfilePath(slug: string): string {
  return `/book/${slug}/`;
}

export function getStaffBookingPath(slug: string): string {
  return `/book/?staff=${slug}`;
}

export function getStaffBySlug(slug: string): Staff | undefined {
  return mockStaff.find((s) => s.slug === slug);
}

export function getStaffByIdOrSlug(idOrSlug: string): Staff | undefined {
  return mockStaff.find((s) => s.id === idOrSlug || s.slug === idOrSlug);
}

export const staticStaffSlugs = mockStaff.map((s) => s.slug);

export function generateStaffSlug(name: string): string {
  const base = name
    .replace(/^(آقای|خانم)\s+/u, "")
    .trim()
    .slice(0, 20);
  const transliterated: Record<string, string> = {
    کریمی: "karimi",
    احمدی: "ahmadi",
    رضایی: "rezaei",
    محمدی: "mohammadi",
    جعفری: "jafari",
  };
  if (transliterated[base]) return transliterated[base];
  return `staff-${Date.now().toString(36)}`;
}

export function getAvatarGradient(name: string): string {
  const colors = [
    "from-accent to-accent-light",
    "from-info to-blue-400",
    "from-success to-green-400",
    "from-purple-500 to-purple-400",
    "from-rose-500 to-rose-400",
  ];
  return colors[name.charCodeAt(0) % colors.length];
}

