"use client";

import { useState } from "react";
import { Check, Link2, Share2 } from "lucide-react";
import { cn } from "@/lib/cn";
import { getStaffProfilePath } from "@/lib/staff/staffProfile";

interface StaffShareButtonProps {
  slug: string;
  variant?: "customer" | "admin";
  className?: string;
}

export default function StaffShareButton({
  slug,
  variant = "customer",
  className,
}: StaffShareButtonProps) {
  const [copied, setCopied] = useState(false);
  const path = getStaffProfilePath(slug);
  const displayUrl = `salon.ir${path.replace(/\/$/, "")}`;

  const handleCopy = async () => {
    const fullUrl =
      typeof window !== "undefined" ? `${window.location.origin}${path}` : displayUrl;
    try {
      await navigator.clipboard.writeText(fullUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      /* clipboard unavailable */
    }
  };

  const isAdmin = variant === "admin";

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      <button
        type="button"
        onClick={handleCopy}
        className={cn(
          "inline-flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all",
          isAdmin
            ? "bg-white/5 border border-white/10 text-[#F5F0E8] hover:border-[#C9A96E]/40 hover:bg-[#C9A96E]/10"
            : "bg-glass-bg border border-glass-border text-text-primary hover:border-accent-border hover:bg-bg-hover"
        )}
      >
        {copied ? (
          <>
            <Check size={16} className="text-success" />
            کپی شد!
          </>
        ) : (
          <>
            {isAdmin ? <Link2 size={16} className="text-[#C9A96E]" /> : <Share2 size={16} className="text-accent" />}
            کپی لینک صفحه
          </>
        )}
      </button>
      <p
        className={cn(
          "text-[10px] text-center truncate dir-ltr",
          isAdmin ? "text-[#A09880]" : "text-text-secondary"
        )}
      >
        {displayUrl}
      </p>
    </div>
  );
}

