"use client";

import { useMemo, useEffect, Suspense } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSearchParams } from "next/navigation";
import Link from "next/link";
import {
  Scissors,
  User,
  Calendar,
  Check,
  ChevronLeft,
  ChevronRight,
  Lock,
} from "lucide-react";
import Logo from "@/components/shared/Logo";
import { ThemeToggle } from "@/components/shared/ThemeToggle";
import ServiceSelector from "@/components/booking/ServiceSelector";
import StaffSelector from "@/components/booking/StaffSelector";
import DateTimePicker from "@/components/booking/DateTimePicker";
import BookingConfirmation from "@/components/booking/BookingConfirmation";
import BookingSuccess from "@/components/booking/BookingSuccess";
import { cn } from "@/lib/cn";
import {
  mockServices,
  mockStaff,
  delay,
  generateBookingCode,
} from "@/lib/mock-data";
import { getStaffByIdOrSlug, getStaffProfilePath } from "@/lib/staff/staffProfile";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import { selectCurrentUser } from "@/store/slices/authSlice";
import { selectStaffRatingsMap } from "@/store/slices/reviewsSlice";
import {
  setStep,
  setSelectedServiceId,
  setServiceCategory,
  setSelectedStaffId,
  setStaffFromProfile,
  setSelectedDate,
  setSelectedTime,
  setTermsAccepted,
  setIsSubmitting,
  setBookingComplete,
  resetBooking,
  selectBookingState,
  type BookingStep,
} from "@/store/slices/bookingSlice";

const steps = [
  { num: 1, label: "انتخاب سرویس", icon: Scissors },
  { num: 2, label: "انتخاب پرسنل", icon: User },
  { num: 3, label: "تاریخ و ساعت", icon: Calendar },
  { num: 4, label: "تأیید نهایی", icon: Check },
];

function BookPageContent() {
  const dispatch = useAppDispatch();
  const searchParams = useSearchParams();
  const user = useAppSelector(selectCurrentUser);
  const {
    currentStep,
    selectedServiceId,
    serviceCategory,
    selectedStaffId,
    staffLocked,
    selectedDate,
    selectedTime,
    termsAccepted,
    isSubmitting,
    bookingComplete,
    bookingCode,
  } = useAppSelector(selectBookingState);
  const staffRatings = useAppSelector(selectStaffRatingsMap);

  const staffParam = searchParams.get("staff");

  useEffect(() => {
    if (!staffParam) return;
    const staff = getStaffByIdOrSlug(staffParam);
    if (staff?.isActive) {
      dispatch(setStaffFromProfile({ staffId: staff.id, lock: true }));
    }
  }, [staffParam, dispatch]);

  const displayName = user?.name ?? "کاربر مهمان";

  const lockedStaff = useMemo(
    () => (staffLocked && selectedStaffId ? mockStaff.find((s) => s.id === selectedStaffId) : null),
    [staffLocked, selectedStaffId]
  );

  const selectedService = useMemo(
    () => mockServices.find((s) => s.id === selectedServiceId) || null,
    [selectedServiceId]
  );

  const selectedStaff = useMemo(
    () => mockStaff.find((s) => s.id === selectedStaffId) || null,
    [selectedStaffId]
  );

  const isAutoStaff = selectedStaffId === "auto";

  const bookableServices = useMemo(() => {
    if (staffLocked && lockedStaff) {
      return mockServices.filter((s) => lockedStaff.services.includes(s.id) && s.isActive);
    }
    return mockServices;
  }, [staffLocked, lockedStaff]);

  const availableStaff = useMemo(() => {
    if (!selectedServiceId) return mockStaff;
    return mockStaff.filter(
      (s) => s.isActive && s.services.includes(selectedServiceId)
    );
  }, [selectedServiceId]);

  const canProceed = () => {
    switch (currentStep) {
      case 1:
        return !!selectedServiceId;
      case 2:
        return !!selectedStaffId;
      case 3:
        return !!selectedDate && !!selectedTime;
      case 4:
        return termsAccepted;
      default:
        return false;
    }
  };

  const handleNext = () => {
    if (currentStep === 1 && staffLocked && canProceed()) {
      dispatch(setStep(3));
      return;
    }
    if (currentStep < 4 && canProceed()) {
      dispatch(setStep((currentStep + 1) as BookingStep));
    }
  };

  const handleBack = () => {
    if (currentStep === 3 && staffLocked) {
      dispatch(setStep(1));
      return;
    }
    if (currentStep > 1) {
      dispatch(setStep((currentStep - 1) as BookingStep));
    }
  };

  const handleSubmit = async () => {
    dispatch(setIsSubmitting(true));
    await delay(1500);
    dispatch(
      setBookingComplete({ complete: true, code: generateBookingCode() })
    );
    dispatch(setIsSubmitting(false));
  };

  const handleNewBooking = () => {
    dispatch(resetBooking());
  };

  if (bookingComplete) {
    return (
      <div className="min-h-screen bg-bg-primary">
        <header className="border-b border-border bg-bg-primary/80 backdrop-blur-md sticky top-0 z-40">
          <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
            <Logo size="sm" />
            <ThemeToggle />
          </div>
        </header>

        <BookingSuccess
          bookingCode={bookingCode}
          service={selectedService}
          staff={selectedStaff}
          isAutoStaff={isAutoStaff}
          date={selectedDate}
          time={selectedTime}
          onNewBooking={handleNewBooking}
        />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-bg-primary">
      <header className="border-b border-border bg-bg-primary/80 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <Logo size="sm" />
          <div className="flex items-center gap-3">
            <ThemeToggle />
            <div className="text-left">
              <p className="text-sm font-medium text-text-primary">
                {displayName}
              </p>
            </div>
            <div className="w-9 h-9 rounded-full bg-gradient-to-br from-accent to-accent-light flex items-center justify-center text-bg-primary font-bold text-sm">
              {displayName.charAt(0)}
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-8">
        {lockedStaff && (
          <motion.div
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-6 flex items-center justify-between gap-3 p-3 rounded-xl bg-accent-bg border border-accent-border"
          >
            <div className="flex items-center gap-2 min-w-0">
              <Lock size={16} className="text-accent shrink-0" />
              <p className="text-sm text-text-primary truncate">
                رزرو با{" "}
                <Link
                  href={getStaffProfilePath(lockedStaff.slug)}
                  className="font-bold text-accent hover:underline"
                >
                  {lockedStaff.name}
                </Link>
              </p>
            </div>
          </motion.div>
        )}

        <div className="mb-10">
          <div className="flex items-center justify-between">
            {steps.map((step, i) => {
              const isSkipped = staffLocked && step.num === 2;
              const isComplete =
                currentStep > step.num || (isSkipped && currentStep >= 3);
              const isCurrent = currentStep === step.num && !isSkipped;

              return (
                <div key={step.num} className="flex items-center">
                  <div className="flex flex-col items-center">
                    <div
                      className={cn(
                        "w-10 h-10 sm:w-12 sm:h-12 rounded-full flex items-center justify-center transition-all duration-300",
                        isComplete || isCurrent
                          ? "bg-gradient-to-br from-accent to-accent-light text-bg-primary"
                          : "bg-bg-elevated text-text-secondary",
                        isSkipped && "opacity-60"
                      )}
                    >
                      {isComplete ? (
                        <Check size={18} />
                      ) : (
                        <step.icon size={18} />
                      )}
                    </div>
                    <span
                      className={cn(
                        "text-[10px] sm:text-xs mt-2 text-center hidden sm:block",
                        isComplete || isCurrent ? "text-accent" : "text-text-secondary"
                      )}
                    >
                      {isSkipped ? "انتخاب‌شده" : step.label}
                    </span>
                  </div>
                  {i < steps.length - 1 && (
                    <div
                      className={cn(
                        "w-8 sm:w-16 lg:w-24 h-0.5 mx-1 sm:mx-2 transition-colors",
                        isComplete ? "bg-accent" : "bg-border"
                      )}
                    />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        <motion.div
          key={currentStep}
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-8"
        >
          <h1 className="text-2xl sm:text-3xl font-bold text-text-primary">
            {steps[currentStep - 1].label}
          </h1>
        </motion.div>

        <AnimatePresence mode="wait">
          {currentStep === 1 && (
            <motion.div
              key="step1"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
            >
              <ServiceSelector
                services={bookableServices}
                selectedId={selectedServiceId}
                onSelect={(id) => dispatch(setSelectedServiceId(id))}
                activeCategory={serviceCategory}
                onCategoryChange={(cat) => dispatch(setServiceCategory(cat))}
              />
            </motion.div>
          )}

          {currentStep === 2 && !staffLocked && (
            <motion.div
              key="step2"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
            >
              <StaffSelector
                staff={availableStaff}
                selectedId={selectedStaffId}
                onSelect={(id) => dispatch(setSelectedStaffId(id))}
                staffRatings={staffRatings}
              />
            </motion.div>
          )}

          {currentStep === 3 && (
            <motion.div
              key="step3"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
            >
              <DateTimePicker
                selectedDate={selectedDate}
                selectedTime={selectedTime}
                onDateSelect={(date) => dispatch(setSelectedDate(date))}
                onTimeSelect={(time) => dispatch(setSelectedTime(time))}
              />
            </motion.div>
          )}

          {currentStep === 4 && (
            <motion.div
              key="step4"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
            >
              <BookingConfirmation
                service={selectedService}
                staff={selectedStaff}
                isAutoStaff={isAutoStaff}
                date={selectedDate}
                time={selectedTime}
                customerName={displayName}
                termsAccepted={termsAccepted}
                onTermsChange={(accepted) =>
                  dispatch(setTermsAccepted(accepted))
                }
                onSubmit={handleSubmit}
                isLoading={isSubmitting}
              />
            </motion.div>
          )}
        </AnimatePresence>

        {currentStep < 4 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex items-center justify-between mt-10 pt-6 border-t border-border"
          >
            <button
              onClick={handleBack}
              disabled={currentStep === 1}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl text-text-secondary hover:text-text-primary hover:bg-bg-elevated transition-colors disabled:opacity-0"
            >
              <ChevronRight size={18} />
              مرحله قبل
            </button>
            <button
              onClick={handleNext}
              disabled={!canProceed()}
              className="btn-gold px-8 py-2.5 font-bold flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              مرحله بعد
              <ChevronLeft size={18} />
            </button>
          </motion.div>
        )}
      </main>
    </div>
  );
}

export default function BookPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen bg-bg-primary flex items-center justify-center text-text-secondary">
          در حال بارگذاری...
        </div>
      }
    >
      <BookPageContent />
    </Suspense>
  );
}

