/**
 * Service revisit intervals and reminder message templates
 */

import type { Service } from "@/lib/data/types";

/** Reference "today" for reminder calculations (demo) */
export const REMINDER_TODAY = "۱۴۰۳/۱۱/۰۱";

export interface ReminderRule {
  category: Service["category"];
  intervalDays: number;
  label: string;
}

export const reminderRules: ReminderRule[] = [
  { category: "color", intervalDays: 42, label: "رنگ و هایلایت" },
  { category: "haircut", intervalDays: 28, label: "کوتاهی و اصلاح" },
  { category: "keratin", intervalDays: 90, label: "کراتین و صافی" },
  { category: "brushing", intervalDays: 60, label: "شینیون و براشینگ" },
  { category: "other", intervalDays: 45, label: "سایر سرویس‌ها" },
];

export const reminderRuleMap = Object.fromEntries(
  reminderRules.map((r) => [r.category, r])
) as Record<Service["category"], ReminderRule>;

export function buildReminderMessage(
  customerName: string,
  serviceName: string,
  daysSince: number,
  urgency: "overdue" | "due" | "soon"
): string {
  const firstName = customerName.split(" ").pop() ?? customerName;
  if (urgency === "overdue") {
    return `سلام ${firstName} عزیز، ${daysSince.toLocaleString("fa-IR")} روز از ${serviceName} شما گذشته. برای حفظ نتیجه، وقت رزرو رسیده!`;
  }
  if (urgency === "due") {
    return `سلام ${firstName}، وقت ${serviceName} شما رسیده. همین هفته رزرو کنید تا نتیجه عالی بمونه.`;
  }
  return `سلام ${firstName}، ${daysSince.toLocaleString("fa-IR")} روز از ${serviceName} شما گذشته. به‌زودی وقت مراجعه مجدد است.`;
}

/**
 * Compute smart service-based reminders from appointment history
 */

import type {
  Appointment,
  Customer,
  Service,
  ServiceReminder,
  ReminderStatus,
  ReminderUrgency,
} from "@/lib/data/types";
import { daysBetweenPersian } from "@/lib/analytics/dashboardAnalytics";
import {
  REMINDER_TODAY,
  buildReminderMessage,
  reminderRuleMap,
} from "@/lib/data/mock/reminderRules";

function getUrgency(
  daysSince: number,
  intervalDays: number
): ReminderUrgency | null {
  const daysUntilDue = intervalDays - daysSince;
  if (daysSince >= intervalDays) return "overdue";
  if (daysUntilDue <= 0) return "due";
  if (daysUntilDue <= 7) return "soon";
  return null;
}

export function computeServiceReminders(
  appointments: Appointment[],
  customers: Customer[],
  services: Service[],
  today: string = REMINDER_TODAY,
  statusOverrides: Record<string, ReminderStatus> = {}
): ServiceReminder[] {
  const serviceMap = Object.fromEntries(services.map((s) => [s.id, s]));
  const customerMap = Object.fromEntries(customers.map((c) => [c.id, c]));

  const latestByCustomerCategory = new Map<
    string,
    { appointment: Appointment; date: string }
  >();

  for (const apt of appointments) {
    if (apt.status !== "completed") continue;
    const service = serviceMap[apt.serviceId];
    if (!service) continue;

    const key = `${apt.customerId}_${service.category}`;
    const existing = latestByCustomerCategory.get(key);
    if (!existing || daysBetweenPersian(existing.date, apt.date) > 0) {
      latestByCustomerCategory.set(key, { appointment: apt, date: apt.date });
    }
  }

  const reminders: ServiceReminder[] = [];

  for (const [, { appointment, date }] of latestByCustomerCategory) {
    const service = serviceMap[appointment.serviceId];
    if (!service) continue;

    const customer = customerMap[appointment.customerId];
    if (!customer || customer.status === "inactive") continue;

    const rule = reminderRuleMap[service.category];
    if (!rule) continue;

    const daysSince = daysBetweenPersian(date, today);
    const urgency = getUrgency(daysSince, rule.intervalDays);
    if (!urgency) continue;

    const id = `rem_${appointment.customerId}_${service.category}`;
    const daysUntilDue = rule.intervalDays - daysSince;

    reminders.push({
      id,
      customerId: appointment.customerId,
      customerName: customer.name,
      customerPhone: customer.phone,
      serviceId: appointment.serviceId,
      serviceName: appointment.serviceName,
      serviceCategory: service.category,
      lastVisitDate: date,
      daysSinceVisit: daysSince,
      intervalDays: rule.intervalDays,
      daysUntilDue,
      urgency,
      status: statusOverrides[id] ?? "pending",
      message: buildReminderMessage(customer.name, appointment.serviceName, daysSince, urgency),
      lastAppointmentId: appointment.id,
    });
  }

  const urgencyOrder: Record<ReminderUrgency, number> = {
    overdue: 0,
    due: 1,
    soon: 2,
  };

  return reminders.sort(
    (a, b) =>
      urgencyOrder[a.urgency] - urgencyOrder[b.urgency] ||
      b.daysSinceVisit - a.daysSinceVisit
  );
}

export { REMINDER_TODAY };

