import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { ReminderStatus, ServiceReminder } from "@/lib/data/types";
import { mockAppointments } from "@/lib/data/mock/appointments";
import { mockCustomers } from "@/lib/data/mock/customers";
import { mockServices } from "@/lib/data/mock/services";
import { computeServiceReminders } from "@/lib/reminders/reminderEngine";

interface RemindersState {
  statusOverrides: Record<string, ReminderStatus>;
  sentTimestamps: Record<string, string>;
}

const initialState: RemindersState = {
  statusOverrides: {},
  sentTimestamps: {},
};

function getAppointments(state: { admin: { initialized: boolean; appointments: typeof mockAppointments } }) {
  return state.admin.initialized ? state.admin.appointments : mockAppointments;
}

function getCustomers(state: { admin: { initialized: boolean; customers: typeof mockCustomers } }) {
  return state.admin.initialized ? state.admin.customers : mockCustomers;
}

const remindersSlice = createSlice({
  name: "reminders",
  initialState,
  reducers: {
    sendReminder: (state, action: PayloadAction<string>) => {
      state.statusOverrides[action.payload] = "sent";
      state.sentTimestamps[action.payload] = new Date().toISOString();
    },
    dismissReminder: (state, action: PayloadAction<string>) => {
      state.statusOverrides[action.payload] = "dismissed";
    },
    resetReminderStatus: (state, action: PayloadAction<string>) => {
      delete state.statusOverrides[action.payload];
      delete state.sentTimestamps[action.payload];
    },
  },
});

export const { sendReminder, dismissReminder, resetReminderStatus } =
  remindersSlice.actions;

type RootSlice = {
  admin: {
    initialized: boolean;
    appointments: typeof mockAppointments;
    customers: typeof mockCustomers;
  };
  reminders: RemindersState;
};

export const selectAllServiceReminders = (state: RootSlice): ServiceReminder[] =>
  computeServiceReminders(
    getAppointments(state),
    getCustomers(state),
    mockServices,
    undefined,
    state.reminders.statusOverrides
  );

export const selectRemindersForCustomer =
  (customerId: string) =>
  (state: RootSlice): ServiceReminder[] =>
    selectAllServiceReminders(state).filter(
      (r) => r.customerId === customerId && r.status !== "dismissed"
    );

export const selectActiveReminders = (state: RootSlice): ServiceReminder[] =>
  selectAllServiceReminders(state).filter((r) => r.status === "pending");

export const selectReminderStats = (state: RootSlice) => {
  const all = selectAllServiceReminders(state);
  const pending = all.filter((r) => r.status === "pending");
  return {
    total: pending.length,
    overdue: pending.filter((r) => r.urgency === "overdue").length,
    due: pending.filter((r) => r.urgency === "due").length,
    soon: pending.filter((r) => r.urgency === "soon").length,
    sent: all.filter((r) => r.status === "sent").length,
  };
};

export default remindersSlice.reducer;

