"use client";

import { motion } from "framer-motion";
import Link from "next/link";
import { Bell, Calendar, Clock, ChevronLeft } from "lucide-react";
import { cn } from "@/lib/cn";
import type { ServiceReminder } from "@/lib/data/types";
import { categoryLabels } from "@/lib/data/mock/services";

interface ReminderCardProps {
  reminder: ServiceReminder;
  onDismiss?: (id: string) => void;
  delay?: number;
}

const urgencyConfig = {
  overdue: {
    label: "عقب‌افتاده",
    color: "text-error",
    bg: "bg-error-bg",
    border: "border-error/30",
    dot: "bg-error",
  },
  due: {
    label: "وقتش رسیده",
    color: "text-warning",
    bg: "bg-warning-bg",
    border: "border-warning/30",
    dot: "bg-warning",
  },
  soon: {
    label: "به‌زودی",
    color: "text-info",
    bg: "bg-info-bg",
    border: "border-info/30",
    dot: "bg-info",
  },
};

export default function ReminderCard({
  reminder,
  onDismiss,
  delay = 0,
}: ReminderCardProps) {
  const config = urgencyConfig[reminder.urgency];

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay }}
      className={cn(
        "rounded-2xl border p-4 sm:p-5",
        "bg-glass-bg backdrop-blur-md border-glass-border",
        reminder.urgency === "overdue" && "border-error/20"
      )}
    >
      <div className="flex items-start gap-3">
        <div
          className={cn(
            "w-10 h-10 rounded-xl flex items-center justify-center shrink-0",
            config.bg
          )}
        >
          <Bell size={18} className={config.color} />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap mb-1">
            <span
              className={cn(
                "px-2 py-0.5 rounded-md text-[10px] font-medium border",
                config.bg,
                config.color,
                config.border
              )}
            >
              {config.label}
            </span>
            <span className="text-[10px] text-text-secondary">
              {categoryLabels[reminder.serviceCategory]}
            </span>
          </div>

          <h3 className="font-bold text-text-primary mb-1">{reminder.serviceName}</h3>
          <p className="text-sm text-text-secondary leading-relaxed mb-3">
            {reminder.message}
          </p>

          <div className="flex flex-wrap items-center gap-3 text-xs text-text-secondary mb-4">
            <span className="flex items-center gap-1">
              <Calendar size={12} />
              آخرین مراجعه: {reminder.lastVisitDate}
            </span>
            <span className="flex items-center gap-1">
              <Clock size={12} />
              {reminder.daysSinceVisit.toLocaleString("fa-IR")} روز گذشته
            </span>
          </div>

