"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { Bell, AlertTriangle, Clock, Send } from "lucide-react";
import ReminderTable from "@/components/admin/ReminderTable";
import { reminderRules } from "@/lib/data/mock/reminderRules";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  dismissReminder,
  resetReminderStatus,
  selectAllServiceReminders,
  selectReminderStats,
  sendReminder,
} from "@/store/slices/remindersSlice";

export default function RemindersPage() {
  const dispatch = useAppDispatch();
  const allReminders = useAppSelector(selectAllServiceReminders);
  const stats = useAppSelector(selectReminderStats);

  const [urgencyFilter, setUrgencyFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState("pending");

  const filtered = useMemo(() => {
    return allReminders.filter((r) => {
      const matchesUrgency = !urgencyFilter || r.urgency === urgencyFilter;
      const matchesStatus = !statusFilter || r.status === statusFilter;
      return matchesUrgency && matchesStatus;
    });
  }, [allReminders, urgencyFilter, statusFilter]);

  const handleSend = (id: string) => {
    dispatch(sendReminder(id));
  };

  const statCards = [
    {
      label: "در انتظار ارسال",
      value: stats.total,
      icon: Bell,
      color: "text-[#C9A96E]",
      bg: "bg-[#C9A96E]/10",
    },
    {
      label: "عقب‌افتاده",
      value: stats.overdue,
      icon: AlertTriangle,
      color: "text-[#E05555]",
      bg: "bg-[#E05555]/10",
    },
    {
      label: "وقت رسیده",
      value: stats.due,
      icon: Clock,
      color: "text-[#E8A84C]",
      bg: "bg-[#E8A84C]/10",
    },
    {
      label: "ارسال‌شده",
      value: stats.sent,
      icon: Send,
      color: "text-[#4CAF82]",
      bg: "bg-[#4CAF82]/10",
    },
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((card, i) => (
          <motion.div
            key={card.label}
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="rounded-2xl bg-white/5 border border-white/10 p-4"
          >
            <div className="flex items-center justify-between mb-2">
              <div className={cn("w-9 h-9 rounded-lg flex items-center justify-center", card.bg)}>
                <card.icon size={18} className={card.color} />
              </div>
            </div>
            <p className="text-2xl font-bold text-[#F5F0E8]">
              {card.value.toLocaleString("fa-IR")}
            </p>
            <p className="text-xs text-[#A09880] mt-1">{card.label}</p>
          </motion.div>
        ))}
      </div>

      <div className="rounded-2xl bg-white/5 border border-white/10 p-4">
        <h3 className="text-sm font-bold text-[#F5F0E8] mb-3">فواصل مراجعه مجدد</h3>
        <div className="flex flex-wrap gap-2">
          {reminderRules.map((rule) => (
            <span
              key={rule.category}
              className="px-3 py-1.5 rounded-lg bg-white/5 text-xs text-[#A09880]"
            >
              {rule.label}: هر{" "}
              <span className="text-[#C9A96E] font-medium">
                {rule.intervalDays.toLocaleString("fa-IR")} روز
              </span>
            </span>
          ))}
        </div>
      </div>

      <div className="flex flex-wrap gap-3">
        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="px-4 py-2.5 rounded-xl bg-white/5 border border-white/10 text-sm text-[#F5F0E8] focus:outline-none focus:border-[#C9A96E]/40"
        >
          <option value="">همه وضعیت‌ها</option>
          <option value="pending">در انتظار</option>
          <option value="sent">ارسال‌شده</option>
          <option value="dismissed">رد شده</option>
        </select>
        <select
          value={urgencyFilter}
          onChange={(e) => setUrgencyFilter(e.target.value)}
          className="px-4 py-2.5 rounded-xl bg-white/5 border border-white/10 text-sm text-[#F5F0E8] focus:outline-none focus:border-[#C9A96E]/40"
        >
          <option value="">همه فوریت‌ها</option>
          <option value="overdue">عقب‌افتاده</option>
          <option value="due">وقت رسیده</option>
          <option value="soon">به‌زودی</option>
        </select>
      </div>

      <ReminderTable
        reminders={filtered}
        onSend={handleSend}
        onDismiss={(id) => dispatch(dismissReminder(id))}
        onReset={(id) => dispatch(resetReminderStatus(id))}
      />
    </div>
  );
}

function cn(...classes: (string | boolean | undefined)[]) {
  return classes.filter(Boolean).join(" ");
}

