import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { CustomerBeautyProfile } from "@/lib/data/types";
import {
  getDefaultBeautyProfile,
  mockBeautyProfiles,
} from "@/lib/data/mock/beautyHistory";

interface BeautyProfileState {
  profiles: Record<string, CustomerBeautyProfile>;
}

const initialState: BeautyProfileState = {
  profiles: Object.fromEntries(
    mockBeautyProfiles.map((p) => [p.customerId, { ...p }])
  ),
};

const beautyProfileSlice = createSlice({
  name: "beautyProfile",
  initialState,
  reducers: {
    upsertBeautyProfile: (state, action: PayloadAction<CustomerBeautyProfile>) => {
      state.profiles[action.payload.customerId] = action.payload;
    },
  },
});

export const { upsertBeautyProfile } = beautyProfileSlice.actions;

export const selectBeautyProfileByCustomerId =
