"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import {
  Sparkles,
  Edit2,
  AlertTriangle,
  Droplets,
  Palette,
  Heart,
  Save,
  X,
  UserCheck,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type { CustomerBeautyProfile, HairType } from "@/lib/data/types";
import { hairTypeLabels } from "@/lib/data/mock/beautyHistory";

interface BeautyProfileCardProps {
  profile: CustomerBeautyProfile;
  onSave: (profile: CustomerBeautyProfile) => void;
  variant?: "admin" | "customer";
}

const hairTypeOptions: { value: HairType | ""; label: string }[] = [
  { value: "", label: "انتخاب نشده" },
  { value: "oily", label: "چرب" },
  { value: "dry", label: "خشک" },
  { value: "normal", label: "معمولی" },
  { value: "damaged", label: "آسیب‌دیده" },
];

const copy = {
  admin: {
    subtitle: "اطلاعات پایدار مشتری — نوع مو، حساسیت‌ها و ترجیحات",
    emptyText: "پروفایل زیبایی این مشتری هنوز تکمیل نشده است.",
    preferencesLabel: "ترجیحات مشتری",
    notesLabel: "یادداشت عمومی",
    notesPlaceholder: "یادداشت‌های کلی درباره مشتری...",
  },
  customer: {
    subtitle: "آرایشگر قبل از نوبت این اطلاعات را می‌بیند",
    emptyText: "پروفایل زیبایی شما هنوز تکمیل نشده. چند ثانیه وقت بگذارید تا سرویس بهتر شود.",
    preferencesLabel: "ترجیحات شما",
    notesLabel: "یادداشت برای آرایشگر",
    notesPlaceholder: "هر نکته‌ای که آرایشگر باید بداند...",
  },
};

export default function BeautyProfileCard({
  profile,
  onSave,
  variant = "admin",
}: BeautyProfileCardProps) {
  const isCustomer = variant === "customer";
  const text = copy[variant];

  const [isEditing, setIsEditing] = useState(false);
  const [form, setForm] = useState(profile);

  const hasSensitivities = !!profile.sensitivities.trim();
  const isEmpty =
    !profile.hairType &&
    !profile.currentHairColor &&
    !profile.sensitivities &&
    !profile.preferences &&
    !profile.notes;

  const handleStartEdit = () => {
    setForm(profile);
    setIsEditing(true);
  };

  const handleCancel = () => {
    setForm(profile);
    setIsEditing(false);
  };

  const handleSave = () => {
    onSave({
      ...form,
      updatedAt: "همین الان",
    });
    setIsEditing(false);
  };

  const inputClass = cn(
    "w-full px-4 py-3 rounded-xl border transition-colors resize-none",
    "focus:outline-none focus:border-accent/50",
    isCustomer
      ? "bg-bg-elevated border-border text-text-primary placeholder:text-text-secondary/50"
      : "bg-white/5 border-white/10 text-[#F5F0E8] placeholder:text-[#A09880]/50 focus:border-[#C9A96E]/50"
  );

  const labelClass = cn(
    "block text-sm font-medium mb-2",
    isCustomer ? "text-text-secondary" : "text-[#A09880]"
  );

  return (
    <div
      className={cn(
        "rounded-2xl overflow-hidden",
        isCustomer
          ? "bg-glass-bg backdrop-blur-md border border-glass-border"
          : "bg-white/5 backdrop-blur-md border border-white/10"
      )}
    >
      <div
        className={cn(
          "flex items-center justify-between p-5 border-b",
          isCustomer ? "border-border" : "border-[#2A2A3A]"
        )}
      >
        <div className="flex items-center gap-3">
          <div
            className={cn(
              "w-10 h-10 rounded-xl flex items-center justify-center",
              isCustomer
                ? "bg-accent-bg border border-accent-border"
                : "bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5"
            )}
          >
            <Sparkles size={20} className="text-accent" />
          </div>
          <div>
            <h2
              className={cn(
                "text-lg font-bold",
                isCustomer ? "text-text-primary" : "text-[#F5F0E8]"
              )}
            >
              پروفایل زیبایی
            </h2>
            <p
              className={cn(
                "text-xs",
                isCustomer ? "text-text-secondary" : "text-[#A09880]"
              )}
            >
              {text.subtitle}
            </p>
          </div>
        </div>

        {!isEditing ? (
          <button
            onClick={handleStartEdit}
            className={cn(
              "px-3 py-2 text-sm font-medium flex items-center gap-2",
              isCustomer ? "btn-gold" : "btn-outline-gold"
            )}
          >
            <Edit2 size={14} />
            {isEmpty ? "تکمیل" : "ویرایش"}
          </button>
        ) : (
          <div className="flex items-center gap-2">
            <button
              onClick={handleCancel}
              className={cn(
                "px-3 py-2 rounded-xl text-sm transition-colors flex items-center gap-1",
                isCustomer
                  ? "text-text-secondary hover:text-text-primary hover:bg-bg-elevated"
                  : "text-[#A09880] hover:text-[#F5F0E8] hover:bg-white/5"
              )}
            >
              <X size={14} />
              انصراف
            </button>
            <button
              onClick={handleSave}
              className="btn-gold px-3 py-2 text-sm font-bold flex items-center gap-1"
            >
              <Save size={14} />
              ذخیره
            </button>
          </div>
        )}
      </div>

      {isCustomer && !isEditing && !isEmpty && (
        <div className="mx-5 mt-5 p-3 rounded-xl bg-accent-bg/50 border border-accent-border flex items-center gap-2">
          <UserCheck size={16} className="text-accent shrink-0" />
          <p className="text-xs text-text-secondary">
            این اطلاعات در پنل آرایشگر و کارنامه زیبایی شما نمایش داده می‌شود.
          </p>
        </div>
      )}

      {hasSensitivities && !isEditing && (
        <div
          className={cn(
            "mx-5 mt-5 p-4 rounded-xl flex items-start gap-3",
            isCustomer
              ? "bg-error-bg border border-error/20"
              : "bg-[#E05555]/10 border border-[#E05555]/20"
          )}
        >
          <AlertTriangle
            size={18}
            className={cn("shrink-0 mt-0.5", isCustomer ? "text-error" : "text-[#E05555]")}
          />
          <div>
            <p
              className={cn(
                "text-sm font-medium mb-1",
                isCustomer ? "text-error" : "text-[#E05555]"
              )}
            >
              حساسیت / آلرژی
            </p>
            <p
              className={cn(
                "text-sm",
                isCustomer ? "text-text-primary/80" : "text-[#F5F0E8]/80"
              )}
            >
              {profile.sensitivities}
            </p>
          </div>
        </div>
      )}

      <div className="p-5">
        {isEditing ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className={labelClass}>نوع مو</label>
              <select
                value={form.hairType ?? ""}
                onChange={(e) =>
                  setForm((prev) => ({
                    ...prev,
                    hairType: (e.target.value || null) as HairType | null,
                  }))
                }
                className={cn(inputClass, "appearance-none [color-scheme:dark]")}
              >
                {hairTypeOptions.map((opt) => (
                  <option
                    key={opt.value}
                    value={opt.value}
                    className={isCustomer ? "bg-bg-card" : "bg-[#12121A]"}
                  >
                    {opt.label}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className={labelClass}>رنگ فعلی مو</label>
              <input
                type="text"
                value={form.currentHairColor}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, currentHairColor: e.target.value }))
                }
                placeholder="مثال: بلوند دودی شماره ۷"
                className={inputClass}
              />
            </div>
            <div className="sm:col-span-2">
              <label className={labelClass}>حساسیت‌ها و آلرژی‌ها</label>
              <textarea
                value={form.sensitivities}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, sensitivities: e.target.value }))
                }
                placeholder="مثال: حساسیت به محصولات آمونیاک‌دار..."
                rows={2}
                className={inputClass}
              />
            </div>
            <div className="sm:col-span-2">
              <label className={labelClass}>{text.preferencesLabel}</label>
              <textarea
                value={form.preferences}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, preferences: e.target.value }))
                }
                placeholder="مثال: پوشش کامل ریشه، ترجیح کوتاهی کلاسیک..."
                rows={2}
                className={inputClass}
              />
            </div>
            <div className="sm:col-span-2">
              <label className={labelClass}>{text.notesLabel}</label>
              <textarea
                value={form.notes}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, notes: e.target.value }))
                }
                placeholder={text.notesPlaceholder}
                rows={2}
                className={inputClass}
              />
            </div>
          </div>
        ) : isEmpty ? (
          <div className="py-8 text-center">
            <Sparkles
              size={40}
              className={cn(
                "mx-auto mb-3 opacity-50",
                isCustomer ? "text-text-secondary" : "text-[#A09880]/50"
              )}
            />
            <p
              className={cn(
                "text-sm mb-4 max-w-sm mx-auto leading-relaxed",
                isCustomer ? "text-text-secondary" : "text-[#A09880]"
              )}
            >
              {text.emptyText}
            </p>
            <button onClick={handleStartEdit} className="btn-gold px-5 py-2 text-sm font-bold">
              تکمیل پروفایل
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {profile.hairType && (
              <ProfileField
                variant={variant}
                icon={Droplets}
                label="نوع مو"
                value={hairTypeLabels[profile.hairType]}
              />
            )}
            {profile.currentHairColor && (
              <ProfileField
                variant={variant}
                icon={Palette}
                label="رنگ فعلی"
                value={profile.currentHairColor}
              />
            )}
            {profile.preferences && (
              <ProfileField
                variant={variant}
                icon={Heart}
                label="ترجیحات"
                value={profile.preferences}
                className="sm:col-span-2 lg:col-span-1"
              />
            )}
            {profile.notes && (
              <ProfileField
                variant={variant}
                icon={Sparkles}
                label="یادداشت"
                value={profile.notes}
                className="sm:col-span-2"
              />
            )}
          </div>
        )}

        {!isEditing && !isEmpty && (
          <p
            className={cn(
              "mt-4 text-xs",
              isCustomer ? "text-text-secondary" : "text-[#A09880]"
            )}
          >
            آخرین بروزرسانی: {profile.updatedAt}
          </p>
        )}
      </div>
    </div>
  );
}

function ProfileField({
  icon: Icon,
  label,
  value,
  className,
  variant = "admin",
}: {
  icon: React.ComponentType<{ size?: number; className?: string }>;
  label: string;
  value: string;
  className?: string;
  variant?: "admin" | "customer";
}) {
  const isCustomer = variant === "customer";

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      className={cn(
        "p-4 rounded-xl border",
        isCustomer
          ? "bg-bg-elevated border-border"
          : "bg-white/5 border-white/5",
        className
      )}
    >
      <div className="flex items-center gap-2 text-accent mb-2">
        <Icon size={14} />
        <span className="text-xs font-medium">{label}</span>
      </div>
      <p
        className={cn(
          "text-sm leading-relaxed",
          isCustomer ? "text-text-primary" : "text-[#F5F0E8]"
        )}
      >
        {value}
      </p>
    </motion.div>
  );
}

