import type { LoyaltyTier } from "@/lib/data/types";

/** Points earned per ۱۰۰۰ تومان spent on completed appointments */
export const POINTS_PER_1000_TOMAN = 10;

/** Bonus points for submitting a review */
export const REVIEW_POINTS = 50;

/** Points referrer earns when friend completes first booking */
export const REFERRER_REWARD_POINTS = 200;

/** Discount percent for referred friend's first booking */
export const REFERRED_DISCOUNT_PERCENT = 15;

/** Redeem: points required → discount in toman */
export const REDEEM_POINTS_STEP = 100;
export const REDEEM_DISCOUNT_TOMAN = 10_000;

export const TIER_THRESHOLDS: { tier: LoyaltyTier; minLifetimePoints: number }[] = [
  { tier: "platinum", minLifetimePoints: 3000 },
  { tier: "gold", minLifetimePoints: 1500 },
  { tier: "silver", minLifetimePoints: 500 },
  { tier: "bronze", minLifetimePoints: 0 },
];

export const tierLabels: Record<LoyaltyTier, string> = {
  bronze: "برنز",
  silver: "نقره‌ای",
  gold: "طلایی",
  platinum: "پلاتین",
};

export const transactionTypeLabels: Record<
  import("@/lib/data/types").LoyaltyTransactionType,
  string
> = {
  appointment_completed: "تکمیل نوبت",
  review_submitted: "ثبت نظر",
  referral_reward: "پاداش دعوت",
  referral_welcome: "هدیه دعوت‌شده",
  points_redeemed: "استفاده از امتیاز",
  welcome_bonus: "امتیاز خوش‌آمد",
};

import type { LoyaltyTier } from "@/lib/data/types";
import {
  POINTS_PER_1000_TOMAN,
  TIER_THRESHOLDS,
  tierLabels,
} from "@/lib/loyalty/loyaltyConfig";

export function computeTierFromLifetimePoints(lifetimePoints: number): LoyaltyTier {
  for (const { tier, minLifetimePoints } of TIER_THRESHOLDS) {
    if (lifetimePoints >= minLifetimePoints) return tier;
  }
  return "bronze";
}

export function computePointsFromPrice(price: number): number {
  return Math.floor((price / 1000) * POINTS_PER_1000_TOMAN);
}

export function computeDiscountFromReferral(price: number, discountPercent: number): number {
  return Math.floor((price * discountPercent) / 100);
}

export function generateReferralCode(customerId: string, customerName: string): string {
  const initials = customerName
    .split(/\s+/)
    .map((w) => w.charAt(0))
    .join("")
    .toUpperCase()
    .slice(0, 4)
    .padEnd(4, "X");
  const suffix = customerId.replace(/\D/g, "").slice(-4).padStart(4, "0");
  return `BEAUTY-${initials}-${suffix}`;
}

export function getReferralShareUrl(code: string): string {
  if (typeof window !== "undefined") {
    return `${window.location.origin}/book?ref=${encodeURIComponent(code)}`;
  }
  return `/book?ref=${encodeURIComponent(code)}`;
}

export function getTierProgress(lifetimePoints: number): {
  tier: LoyaltyTier;
  label: string;
  nextTier: LoyaltyTier | null;
  nextLabel: string | null;
  progressPercent: number;
  pointsToNext: number;
} {
  const tier = computeTierFromLifetimePoints(lifetimePoints);
  const label = tierLabels[tier];
  const currentIdx = TIER_THRESHOLDS.findIndex((t) => t.tier === tier);
  const nextTierEntry = currentIdx > 0 ? TIER_THRESHOLDS[currentIdx - 1] : null;

  if (!nextTierEntry) {
    return {
      tier,
      label,
      nextTier: null,
      nextLabel: null,
      progressPercent: 100,
      pointsToNext: 0,
    };
  }

  const currentMin = TIER_THRESHOLDS[currentIdx].minLifetimePoints;
  const nextMin = nextTierEntry.minLifetimePoints;
  const range = nextMin - currentMin;
  const progress = Math.min(100, Math.round(((lifetimePoints - currentMin) / range) * 100));

  return {
    tier,
    label,
    nextTier: nextTierEntry.tier,
    nextLabel: tierLabels[nextTierEntry.tier],
    progressPercent: progress,
    pointsToNext: Math.max(0, nextMin - lifetimePoints),
  };
}

import type {
  CustomerLoyaltyAccount,
  LoyaltyTransaction,
  Referral,
} from "@/lib/data/types";
import { generateReferralCode } from "@/lib/loyalty/loyaltyUtils";
import { computeTierFromLifetimePoints } from "@/lib/loyalty/loyaltyUtils";
import {
  REFERRED_DISCOUNT_PERCENT,
  REFERRER_REWARD_POINTS,
} from "@/lib/loyalty/loyaltyConfig";

function account(
  customerId: string,
  name: string,
  balance: number,
  lifetime: number
): CustomerLoyaltyAccount {
  return {
    customerId,
    pointsBalance: balance,
    lifetimePoints: lifetime,
    tier: computeTierFromLifetimePoints(lifetime),
    referralCode: generateReferralCode(customerId, name),
