import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type {
  CustomerLoyaltyAccount,
  LoyaltyTransaction,
  LoyaltyTransactionType,
  Referral,
} from "@/lib/data/types";
import {
  mockLoyaltyAccounts,
  mockLoyaltyTransactions,
  mockReferrals,
} from "@/lib/data/mock/loyalty";
import {
  REDEEM_DISCOUNT_TOMAN,
  REDEEM_POINTS_STEP,
  REFERRED_DISCOUNT_PERCENT,
  REFERRER_REWARD_POINTS,
  REVIEW_POINTS,
} from "@/lib/loyalty/loyaltyConfig";
import {
  computePointsFromPrice,
  computeTierFromLifetimePoints,
  generateReferralCode,
} from "@/lib/loyalty/loyaltyUtils";

interface LoyaltyState {
  accounts: Record<string, CustomerLoyaltyAccount>;
  transactions: LoyaltyTransaction[];
  referrals: Referral[];
  /** Applied referral code during booking (referrer's code) */
  appliedReferralCode: string | null;
  appliedReferralDiscountPercent: number;
}

const initialState: LoyaltyState = {
  accounts: Object.fromEntries(
    mockLoyaltyAccounts.map((a) => [a.customerId, { ...a }])
  ),
  transactions: mockLoyaltyTransactions.map((t) => ({ ...t })),
  referrals: mockReferrals.map((r) => ({ ...r })),
  appliedReferralCode: null,
  appliedReferralDiscountPercent: 0,
};

function ensureAccount(
  state: LoyaltyState,
  customerId: string,
  customerName: string
): CustomerLoyaltyAccount {
  if (!state.accounts[customerId]) {
    state.accounts[customerId] = {
      customerId,
      pointsBalance: 0,
      lifetimePoints: 0,
      tier: "bronze",
      referralCode: generateReferralCode(customerId, customerName),
      updatedAt: new Date().toISOString(),
    };
  }
  return state.accounts[customerId];
}

function addTransaction(
  state: LoyaltyState,
  payload: {
    customerId: string;
    type: LoyaltyTransactionType;
    points: number;
    description: string;
    relatedId?: string | null;
  }
) {
  const tx: LoyaltyTransaction = {
    id: `lt_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    customerId: payload.customerId,
    type: payload.type,
    points: payload.points,
    description: payload.description,
    relatedId: payload.relatedId ?? null,
    createdAt: new Date().toISOString(),
  };
  state.transactions.unshift(tx);
  return tx;
}

const loyaltySlice = createSlice({
  name: "loyalty",
  initialState,
  reducers: {
    setAppliedReferralCode: (
      state,
      action: PayloadAction<{ code: string | null; discountPercent?: number }>
    ) => {
      state.appliedReferralCode = action.payload.code;
      state.appliedReferralDiscountPercent =
        action.payload.code != null
          ? (action.payload.discountPercent ?? REFERRED_DISCOUNT_PERCENT)
          : 0;
    },
    clearAppliedReferralCode: (state) => {
      state.appliedReferralCode = null;
      state.appliedReferralDiscountPercent = 0;
    },
    earnAppointmentPoints: (
      state,
      action: PayloadAction<{
        customerId: string;
        customerName: string;
        price: number;
        appointmentId: string;
        serviceName: string;
      }>
    ) => {
      const { customerId, customerName, price, appointmentId, serviceName } =
        action.payload;
      const points = computePointsFromPrice(price);
      if (points <= 0) return;

      const account = ensureAccount(state, customerId, customerName);
      account.pointsBalance += points;
      account.lifetimePoints += points;
      account.tier = computeTierFromLifetimePoints(account.lifetimePoints);
      account.updatedAt = new Date().toISOString();

      addTransaction(state, {
        customerId,
        type: "appointment_completed",
        points,
        description: `نوبت ${serviceName} — ${price.toLocaleString("fa-IR")} تومان`,
        relatedId: appointmentId,
      });
    },
    earnReviewPoints: (
      state,
      action: PayloadAction<{
        customerId: string;
        customerName: string;
        appointmentId: string;
        staffName: string;
      }>
    ) => {
      const { customerId, customerName, appointmentId, staffName } = action.payload;
      const alreadyEarned = state.transactions.some(
        (t) =>
          t.customerId === customerId &&
          t.type === "review_submitted" &&
          t.relatedId === appointmentId
      );
      if (alreadyEarned) return;

      const account = ensureAccount(state, customerId, customerName);
      account.pointsBalance += REVIEW_POINTS;
      account.lifetimePoints += REVIEW_POINTS;
      account.tier = computeTierFromLifetimePoints(account.lifetimePoints);
      account.updatedAt = new Date().toISOString();

      addTransaction(state, {
        customerId,
        type: "review_submitted",
        points: REVIEW_POINTS,
        description: `ثبت نظر برای ${staffName}`,
        relatedId: appointmentId,
      });
    },
    redeemPoints: (
      state,
      action: PayloadAction<{ customerId: string; steps?: number }>
    ) => {
      const account = state.accounts[action.payload.customerId];
      if (!account) return;

      const steps = action.payload.steps ?? 1;
      const pointsCost = steps * REDEEM_POINTS_STEP;
      if (account.pointsBalance < pointsCost) return;

      account.pointsBalance -= pointsCost;
      account.updatedAt = new Date().toISOString();

      addTransaction(state, {
        customerId: action.payload.customerId,
        type: "points_redeemed",
        points: -pointsCost,
        description: `تبدیل به ${(steps * REDEEM_DISCOUNT_TOMAN).toLocaleString("fa-IR")} تومان تخفیف`,
        relatedId: null,
      });
    },
    completeReferralBooking: (
      state,
      action: PayloadAction<{
        referralCode: string;
        referredCustomerId: string;
        referredName: string;
        referredPhone: string;
      }>
    ) => {
      const { referralCode, referredCustomerId, referredName, referredPhone } =
        action.payload;

      const referrerAccount = Object.values(state.accounts).find(
        (a) => a.referralCode === referralCode
      );
      if (!referrerAccount) return;
      if (referrerAccount.customerId === referredCustomerId) return;

      const existing = state.referrals.find(
        (r) =>
          r.referralCode === referralCode &&
          r.referredCustomerId === referredCustomerId &&
          r.status === "completed"
      );
      if (existing) return;

      const referral: Referral = {
        id: `ref_${Date.now()}`,
        referrerCustomerId: referrerAccount.customerId,
        referrerName: "",
        referralCode,
        referredCustomerId,
        referredName,
        referredPhone,
        status: "completed",
        referrerRewardPoints: REFERRER_REWARD_POINTS,
        referredDiscountPercent: REFERRED_DISCOUNT_PERCENT,
        completedAt: new Date().toISOString(),
        createdAt: new Date().toISOString(),
      };
      state.referrals.unshift(referral);

      referrerAccount.pointsBalance += REFERRER_REWARD_POINTS;
      referrerAccount.lifetimePoints += REFERRER_REWARD_POINTS;
      referrerAccount.tier = computeTierFromLifetimePoints(
        referrerAccount.lifetimePoints
      );
      referrerAccount.updatedAt = new Date().toISOString();

      addTransaction(state, {
        customerId: referrerAccount.customerId,
        type: "referral_reward",
        points: REFERRER_REWARD_POINTS,
        description: `دعوت ${referredName} — اولین نوبت تکمیل شد`,
        relatedId: referral.id,
      });

      const referredAccount = ensureAccount(state, referredCustomerId, referredName);
      addTransaction(state, {
        customerId: referredCustomerId,
        type: "referral_welcome",
        points: 0,
        description: `تخفیف ${REFERRED_DISCOUNT_PERCENT}٪ اولین نوبت با کد ${referralCode}`,
        relatedId: referral.id,
      });

      void referredAccount;
    },
  },
});

export const {
  setAppliedReferralCode,
  clearAppliedReferralCode,
  earnAppointmentPoints,
  earnReviewPoints,
  redeemPoints,
  completeReferralBooking,
} = loyaltySlice.actions;

export const selectLoyaltyAccountByCustomerId =
  (customerId: string) => (state: { loyalty: LoyaltyState }) => {
    const account = state.loyalty.accounts[customerId];
    if (account) return account;
    return {
      customerId,
      pointsBalance: 0,
      lifetimePoints: 0,
      tier: "bronze" as const,
      referralCode: generateReferralCode(customerId, "مشتری"),
      updatedAt: "",
    };
  };

export const selectTransactionsByCustomerId =
  (customerId: string) => (state: { loyalty: LoyaltyState }) =>
    state.loyalty.transactions.filter((t) => t.customerId === customerId);

export const selectReferralsByReferrerId =
  (customerId: string) => (state: { loyalty: LoyaltyState }) =>
    state.loyalty.referrals.filter((r) => r.referrerCustomerId === customerId);

export const selectAppliedReferral = (state: { loyalty: LoyaltyState }) => ({
  code: state.loyalty.appliedReferralCode,
  discountPercent: state.loyalty.appliedReferralDiscountPercent,
});

export const selectAllLoyaltyAccounts = (state: { loyalty: LoyaltyState }) =>
  Object.values(state.loyalty.accounts).sort(
    (a, b) => b.pointsBalance - a.pointsBalance
  );

export const selectAllReferrals = (state: { loyalty: LoyaltyState }) =>
  [...state.loyalty.referrals].sort((a, b) =>
    b.createdAt.localeCompare(a.createdAt)
  );

export const selectLoyaltyStats = (state: { loyalty: LoyaltyState }) => {
  const accounts = Object.values(state.loyalty.accounts);
  const referrals = state.loyalty.referrals;
  return {
    totalMembers: accounts.length,
    totalPointsBalance: accounts.reduce((s, a) => s + a.pointsBalance, 0),
    totalLifetimePoints: accounts.reduce((s, a) => s + a.lifetimePoints, 0),
    completedReferrals: referrals.filter((r) => r.status === "completed").length,
    pendingReferrals: referrals.filter((r) => r.status === "pending").length,
    goldMembers: accounts.filter(
      (a) => a.tier === "gold" || a.tier === "platinum"
    ).length,
  };
};

export const validateReferralCode =
  (code: string, currentCustomerId?: string) =>
  (state: { loyalty: LoyaltyState }): { valid: boolean; message: string } => {
    const normalized = code.trim().toUpperCase();
    if (!normalized) {
      return { valid: false, message: "کد دعوت را وارد کنید" };
    }
    const owner = Object.values(state.loyalty.accounts).find(
      (a) => a.referralCode === normalized
    );
    if (!owner) {
      return { valid: false, message: "کد دعوت معتبر نیست" };
    }
    if (currentCustomerId && owner.customerId === currentCustomerId) {
      return { valid: false, message: "نمی‌توانید از کد خودتان استفاده کنید" };
    }
    return { valid: true, message: `تخفیف ${REFERRED_DISCOUNT_PERCENT}٪ اعمال می‌شود` };
  };

export default loyaltySlice.reducer;

