"use client";

import { motion } from "framer-motion";
import { Award, TrendingUp, Sparkles } from "lucide-react";
import { cn } from "@/lib/cn";
import type { CustomerLoyaltyAccount, LoyaltyTier } from "@/lib/data/types";
import { tierLabels } from "@/lib/loyalty/loyaltyConfig";
import { getTierProgress } from "@/lib/loyalty/loyaltyUtils";

interface LoyaltyPointsCardProps {
  account: CustomerLoyaltyAccount;
  onRedeem?: () => void;
  canRedeem?: boolean;
  delay?: number;
}

const tierStyles: Record<
  LoyaltyTier,
  { gradient: string; icon: string; border: string }
> = {
  bronze: {
    gradient: "from-amber-700/20 to-transparent",
    icon: "text-amber-600",
    border: "border-amber-600/30",
  },
  silver: {
    gradient: "from-slate-400/20 to-transparent",
    icon: "text-slate-300",
    border: "border-slate-400/30",
  },
  gold: {
    gradient: "from-accent/25 to-transparent",
    icon: "text-accent",
    border: "border-accent/40",
  },
  platinum: {
    gradient: "from-violet-400/20 to-transparent",
    icon: "text-violet-300",
    border: "border-violet-400/30",
  },
};

export default function LoyaltyPointsCard({
  account,
  onRedeem,
  canRedeem = false,
  delay = 0,
}: LoyaltyPointsCardProps) {
  const progress = getTierProgress(account.lifetimePoints);
  const style = tierStyles[account.tier];

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay }}
      className={cn(
        "rounded-2xl bg-glass-bg backdrop-blur-md border border-glass-border overflow-hidden",
        style.border
      )}
    >
      <div
        className={cn(
          "p-5 bg-gradient-to-l",
          style.gradient
        )}
      >
        <div className="flex items-start justify-between gap-4">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Award size={18} className={style.icon} />
              <span className="text-xs text-text-secondary">سطح وفاداری</span>
            </div>
            <p className={cn("text-2xl font-bold", style.icon)}>
              {tierLabels[account.tier]}
            </p>
          </div>
          <div className="text-left">
            <p className="text-xs text-text-secondary mb-1">موجودی امتیاز</p>
            <p className="text-3xl font-bold text-text-primary">
              {account.pointsBalance.toLocaleString("fa-IR")}
            </p>
          </div>
        </div>

        {progress.nextTier && (
          <div className="mt-4">
            <div className="flex justify-between text-[10px] text-text-secondary mb-1.5">
              <span>{progress.label}</span>
              <span>
                {progress.pointsToNext.toLocaleString("fa-IR")} امتیاز تا{" "}
                {progress.nextLabel}
              </span>
            </div>
            <div className="h-1.5 rounded-full bg-bg-elevated overflow-hidden">
              <motion.div
                initial={{ width: 0 }}
                animate={{ width: `${progress.progressPercent}%` }}
                transition={{ duration: 0.8, delay: delay + 0.2 }}
                className="h-full bg-gradient-to-l from-accent to-accent-light rounded-full"
              />
            </div>
          </div>
        )}
      </div>

      <div className="p-4 flex flex-wrap items-center justify-between gap-3 border-t border-border">
        <div className="flex items-center gap-2 text-xs text-text-secondary">
          <TrendingUp size={14} className="text-accent" />
          <span>
            مجموع امتیاز:{" "}
            <span className="text-text-primary font-medium">
              {account.lifetimePoints.toLocaleString("fa-IR")}
            </span>
          </span>
        </div>
        {onRedeem && (
          <button
            type="button"
            onClick={onRedeem}
            disabled={!canRedeem}
            className="btn-gold px-4 py-2 text-xs font-bold inline-flex items-center gap-1.5 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            <Sparkles size={14} />
            تبدیل امتیاز
          </button>
        )}
      </div>
    </motion.div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Gift, Copy, Check, Share2, Users } from "lucide-react";
import { cn } from "@/lib/cn";
import type { Referral } from "@/lib/data/types";
import { REFERRED_DISCOUNT_PERCENT, REFERRER_REWARD_POINTS } from "@/lib/loyalty/loyaltyConfig";
import { getReferralShareUrl } from "@/lib/loyalty/loyaltyUtils";

interface ReferralShareCardProps {
  referralCode: string;
  referrals: Referral[];
  delay?: number;
}

export default function ReferralShareCard({
  referralCode,
  referrals,
  delay = 0,
}: ReferralShareCardProps) {
  const [copied, setCopied] = useState(false);
  const shareUrl = getReferralShareUrl(referralCode);
  const completed = referrals.filter((r) => r.status === "completed");

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      /* clipboard unavailable */
    }
  };

  const handleShare = async () => {
    const text = `به سالن زیبایی ما بیا! با کد ${referralCode} ${REFERRED_DISCOUNT_PERCENT}٪ تخفیف اولین نوبتت رو بگیر 🎁`;
    if (navigator.share) {
      try {
        await navigator.share({ title: "دعوت به سالن زیبایی", text, url: shareUrl });
        return;
      } catch {
        /* user cancelled */
      }
    }
    handleCopy();
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay }}
      className="rounded-2xl bg-glass-bg backdrop-blur-md border border-glass-border overflow-hidden"
    >
      <div className="p-5 bg-gradient-to-l from-accent/15 to-transparent border-b border-border">
        <div className="flex items-center gap-2 mb-2">
          <Gift size={20} className="text-accent" />
          <h3 className="font-bold text-text-primary">دعوت از دوستان</h3>
        </div>
        <p className="text-sm text-text-secondary leading-relaxed">
          به دوستت{" "}
          <span className="text-accent font-medium">{REFERRED_DISCOUNT_PERCENT}٪ تخفیف</span>{" "}
          بده، خودت هم{" "}
          <span className="text-accent font-medium">
            {REFERRER_REWARD_POINTS.toLocaleString("fa-IR")} امتیاز
          </span>{" "}
          بگیر!
        </p>
      </div>

      <div className="p-4 space-y-4">
        <div>
          <p className="text-xs text-text-secondary mb-2">کد دعوت اختصاصی شما</p>
          <div className="flex items-center gap-2">
            <code className="flex-1 px-4 py-3 rounded-xl bg-bg-elevated border border-border text-accent font-bold text-center tracking-wider text-sm">
              {referralCode}
            </code>
            <button
              type="button"
              onClick={handleCopy}
              className={cn(
                "w-11 h-11 rounded-xl flex items-center justify-center transition-colors shrink-0",
                copied
                  ? "bg-success-bg text-success"
                  : "bg-accent-bg text-accent hover:bg-accent/20"
              )}
              aria-label="کپی لینک"
            >
              {copied ? <Check size={18} /> : <Copy size={18} />}
            </button>
          </div>
        </div>

        <div className="flex gap-2">
          <button
            type="button"
            onClick={handleShare}
            className="flex-1 btn-gold py-2.5 text-sm font-bold inline-flex items-center justify-center gap-2"
          >
            <Share2 size={16} />
            اشتراک‌گذاری
          </button>
        </div>

        {completed.length > 0 && (
          <div className="pt-3 border-t border-border">
            <div className="flex items-center gap-2 mb-3">
              <Users size={14} class className="text-text-secondary" />
              <span className="text-xs text-text-secondary">
                {completed.length.toLocaleString("fa-IR")} دعوت موفق
              </span>
            </div>
            <ul className="space-y-2">
              {completed.slice(0, 3).map((ref) => (
                <li
                  key={ref.id}
                  className="flex items-center justify-between text-xs px-3 py-2 rounded-lg bg-bg-elevated"
                >
                  <span className="text-text-primary">{ref.referredName ?? "—"}</span>
                  <span className="text-accent font-medium">
