/**
 * Staff performance analytics — HR comparison metrics
 */

import type {
  Appointment,
  Review,
  Staff,
  StaffPerformanceMetric,
  StaffPerformanceSummary,
} from "@/lib/data/types";
import { getPublishedReviews } from "@/lib/reviews/utils";
import { ANALYTICS_WEEK_DATES } from "@/lib/analytics/dashboardAnalytics";

export type PerformancePeriod = "all" | "week";

function filterAppointmentsByPeriod(
  appointments: Appointment[],
  period: PerformancePeriod
): Appointment[] {
  if (period === "all") return appointments;
  return appointments.filter((a) =>
    (ANALYTICS_WEEK_DATES as readonly string[]).includes(a.date)
  );
}

function round1(n: number): number {
  return Math.round(n * 10) / 10;
}

export function computeStaffPerformance(
  staff: Staff[],
  appointments: Appointment[],
  reviews: Review[],
  period: PerformancePeriod = "all"
): StaffPerformanceSummary {
  const filtered = filterAppointmentsByPeriod(appointments, period);
  const publishedReviews = getPublishedReviews(reviews);

  const metrics: StaffPerformanceMetric[] = staff.map((member) => {
    const staffAppts = filtered.filter((a) => a.staffId === member.id);
    const total = staffAppts.length;
    const completed = staffAppts.filter((a) => a.status === "completed").length;
    const confirmed = staffAppts.filter((a) => a.status === "confirmed").length;
    const cancelled = staffAppts.filter((a) => a.status === "cancelled").length;
    const noShow = staffAppts.filter((a) => a.status === "no_show").length;
    const resolved = completed + cancelled + noShow;

    const staffReviews = publishedReviews.filter((r) => r.staffId === member.id);
    const reviewCount = staffReviews.length;
    const averageRating =
      reviewCount === 0
        ? 0
        : round1(staffReviews.reduce((s, r) => s + r.rating, 0) / reviewCount);

    const totalRevenue = staffAppts
      .filter((a) => a.status === "completed")
      .reduce((sum, a) => sum + a.price, 0);

    const completionRate = resolved > 0 ? round1((completed / resolved) * 100) : 0;
    const cancellationRate = total > 0 ? round1((cancelled / total) * 100) : 0;
    const noShowRate = total > 0 ? round1((noShow / total) * 100) : 0;

    return {
      staffId: member.id,
      staffName: member.name,
      role: member.role,
      isActive: member.isActive,
      totalAppointments: total,
      completedCount: completed,
      confirmedCount: confirmed,
      cancelledCount: cancelled,
      noShowCount: noShow,
      completionRate,
      cancellationRate,
      noShowRate,
      totalRevenue,
      averageRating,
      reviewCount,
      performanceScore: 0,
      rank: 0,
    };
  });

  const maxRevenue = Math.max(...metrics.map((m) => m.totalRevenue), 1);

  for (const m of metrics) {
    const ratingNorm = m.averageRating > 0 ? (m.averageRating / 5) * 100 : 50;
    const revenueNorm = (m.totalRevenue / maxRevenue) * 100;
    const cancelPenalty = Math.max(0, 100 - m.cancellationRate * 3);
    const noShowPenalty = Math.max(0, 100 - m.noShowRate * 4);

    m.performanceScore = Math.round(
      m.completionRate * 0.35 +
        ratingNorm * 0.25 +
        revenueNorm * 0.2 +
        cancelPenalty * 0.12 +
        noShowPenalty * 0.08
    );
  }

  const ranked = [...metrics].sort((a, b) => b.performanceScore - a.performanceScore);
  ranked.forEach((m, i) => {
    const original = metrics.find((x) => x.staffId === m.staffId)!;
    original.rank = i + 1;
  });

  const activeMetrics = metrics.filter((m) => m.isActive && m.totalAppointments > 0);

  const pickMax = (
    key: keyof Pick<
      StaffPerformanceMetric,
      "performanceScore" | "cancelledCount" | "noShowCount" | "totalRevenue" | "averageRating"
    >
  ) => {
    if (activeMetrics.length === 0) return null;
    return activeMetrics.reduce((best, cur) =>
      cur[key] > best[key] ? cur : best
    );
  };

  return {
    metrics: [...metrics].sort((a, b) => a.rank - b.rank),
    topPerformer: pickMax("performanceScore"),
    mostCancellations: pickMax("cancelledCount"),
    mostNoShows: pickMax("noShowCount"),
    highestRevenue: pickMax("totalRevenue"),
    bestRated:
      activeMetrics.filter((m) => m.reviewCount > 0).length > 0
        ? activeMetrics
            .filter((m) => m.reviewCount > 0)
            .reduce((best, cur) => (cur.averageRating > best.averageRating ? cur : best))
        : null,
  };
}

import type { RootState } from "@/store";
import type { PerformancePeriod } from "@/lib/analytics/staffPerformance";
import { computeStaffPerformance } from "@/lib/analytics/staffPerformance";
import { mockAppointments, mockStaff } from "@/lib/data/mock";

function getAppointments(state: RootState) {
  return state.admin.initialized ? state.admin.appointments : mockAppointments;
}

function getStaff(state: RootState) {
  return state.admin.initialized ? state.admin.staff : mockStaff;
}

export const selectStaffPerformanceReport =
  (period: PerformancePeriod = "all") =>
  (state: RootState) =>
    computeStaffPerformance(
      getStaff(state),
      getAppointments(state),
      state.reviews.reviews,
      period
    );

