"use client";

import { motion } from "framer-motion";
import Link from "next/link";
import { Star, ChevronLeft } from "lucide-react";
import { cn } from "@/lib/cn";
import type { StaffPerformanceMetric } from "@/lib/data/types";
import { getStaffProfilePath } from "@/lib/staff/staffProfile";
import { mockStaff } from "@/lib/data/mock/staff";

export type PerformanceSortKey =
  | "rank"
  | "performanceScore"
  | "totalRevenue"
  | "averageRating"
  | "cancelledCount"
  | "completionRate";

interface StaffPerformanceTableProps {
  metrics: StaffPerformanceMetric[];
  sortKey: PerformanceSortKey;
  onSort: (key: PerformanceSortKey) => void;
}

const sortLabels: Record<PerformanceSortKey, string> = {
  rank: "رتبه",
  performanceScore: "امتیاز",
  totalRevenue: "درآمد",
  averageRating: "رضایت",
  cancelledCount: "لغو",
  completionRate: "تکمیل",
};

function SortHeader({
  label,
  sortKey,
  current,
  onSort,
  className,
}: {
  label: string;
  sortKey: PerformanceSortKey;
  current: PerformanceSortKey;
  onSort: (k: PerformanceSortKey) => void;
  className?: string;
}) {
  return (
    <th className={cn("text-right px-4 py-4 text-sm font-medium", className)}>
      <button
        type="button"
        onClick={() => onSort(sortKey)}
        className={cn(
          "transition-colors",
          current === sortKey ? "text-[#C9A96E]" : "text-[#A09880] hover:text-[#F5F0E8]"
        )}
      >
        {label}
        {current === sortKey && " ↓"}
      </button>
    </th>
  );
}

function ScoreBar({ value, max = 100, color = "bg-[#C9A96E]" }: { value: number; max?: number; color?: string }) {
  const pct = max > 0 ? Math.min(100, (value / max) * 100) : 0;
  return (
    <div className="h-1.5 w-full max-w-[80px] rounded-full bg-white/10 overflow-hidden">
      <div className={cn("h-full rounded-full", color)} style={{ width: `${pct}%` }} />
    </div>
  );
}

export default function StaffPerformanceTable({
  metrics,
  sortKey,
  onSort,
}: StaffPerformanceTableProps) {
  const maxScore = Math.max(...metrics.map((m) => m.performanceScore), 1);

  if (metrics.length === 0) {
    return (
      <div className="rounded-2xl bg-white/5 border border-white/10 p-12 text-center">
        <p className="text-[#A09880]">داده عملکردی برای نمایش وجود ندارد</p>
      </div>
    );
  }

  return (
    <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b border-[#2A2A3A]">
              <SortHeader label={sortLabels.rank} sortKey="rank" current={sortKey} onSort={onSort} />
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">پرسنل</th>
              <SortHeader
                label={sortLabels.performanceScore}
                sortKey="performanceScore"
                current={sortKey}
                onSort={onSort}
              />
              <SortHeader
                label={sortLabels.totalRevenue}
                sortKey="totalRevenue"
                current={sortKey}
                onSort={onSort}
                className="hidden md:table-cell"
              />
              <SortHeader
                label={sortLabels.averageRating}
                sortKey="averageRating"
                current={sortKey}
                onSort={onSort}
                className="hidden lg:table-cell"
              />
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880] hidden sm:table-cell">
                نوبت‌ها
              </th>
              <SortHeader
                label={sortLabels.completionRate}
                sortKey="completionRate"
                current={sortKey}
                onSort={onSort}
                className="hidden lg:table-cell"
              />
              <SortHeader
                label={sortLabels.cancelledCount}
                sortKey="cancelledCount"
                current={sortKey}
                onSort={onSort}
              />
            </tr>
          </thead>
          <tbody className="divide-y divide-[#2A2A3A]">
            {metrics.map((m, i) => {
              const slug = mockStaff.find((s) => s.id === m.staffId)?.slug;
              return (
                <motion.tr
                  key={m.staffId}
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.03 }}
                  className={cn(
                    "hover:bg-white/[0.02] transition-colors",
                    !m.isActive && "opacity-50"
                  )}
                >
                  <td className="px-4 py-4">
                    <span
                      className={cn(
                        "inline-flex w-7 h-7 items-center justify-center rounded-lg text-xs font-bold",
                        m.rank === 1
                          ? "bg-[#C9A96E]/20 text-[#C9A96E]"
                          : "bg-white/5 text-[#A09880]"
                      )}
                    >
                      {m.rank.toLocaleString("fa-IR")}
