  const report = useAppSelector(selectStaffPerformanceReport(period));

  const sortedMetrics = useMemo(() => {
    const list = [...report.metrics];
    list.sort((a, b) => {
      switch (sortKey) {
        case "rank":
          return a.rank - b.rank;
        case "performanceScore":
          return b.performanceScore - a.performanceScore;
        case "totalRevenue":
          return b.totalRevenue - a.totalRevenue;
        case "averageRating":
          return b.averageRating - a.averageRating;
        case "cancelledCount":
          return b.cancelledCount - a.cancelledCount;
        case "completionRate":
          return b.completionRate - a.completionRate;
        default:
