import type { WaitlistEntry } from "@/lib/data/types";

export function buildSlotKey(staffId: string, date: string, time: string): string {
  return `${staffId}|${date}|${time}`;
}

export function entriesForSlot(
  entries: WaitlistEntry[],
  staffId: string,
  date: string,
  time: string
): WaitlistEntry[] {
  const key = buildSlotKey(staffId, date, time);
  return entries
    .filter(
      (e) =>
        buildSlotKey(e.staffId, e.date, e.time) === key &&
        (e.status === "waiting" || e.status === "notified")
    )
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt));
}

export function nextWaitingEntry(
  entries: WaitlistEntry[],
  staffId: string,
  date: string,
  time: string
): WaitlistEntry | null {
  const waiting = entriesForSlot(entries, staffId, date, time).filter(
    (e) => e.status === "waiting"
  );
  return waiting[0] ?? null;
}

export function recalculateQueuePositions(
  entries: WaitlistEntry[],
  staffId: string,
  date: string,
  time: string
): WaitlistEntry[] {
  const key = buildSlotKey(staffId, date, time);
  const slotEntries = entries
    .filter(
      (e) =>
        buildSlotKey(e.staffId, e.date, e.time) === key && e.status === "waiting"
    )
    .sort((a, b) => a.createdAt.localeCompare(b.createdAt));

  slotEntries.forEach((entry, index) => {
    const original = entries.find((e) => e.id === entry.id);
    if (original) original.queuePosition = index + 1;
  });

  return entries;
}

/** Map booking day index (0=today) to demo Persian dates aligned with mock appointments */
import { ANALYTICS_WEEK_DATES } from "@/lib/analytics/dashboardAnalytics";

export function bookingDayIndexToPersianDate(dayIndex: number): string {
  return ANALYTICS_WEEK_DATES[dayIndex] ?? ANALYTICS_WEEK_DATES[0];
}

export function formatWaitlistMessage(
  staffName: string,
  serviceName: string,
  date: string,
  time: string
): string {
  return `خبر خوب! نوبت ${serviceName} با ${staffName} در ${date} ساعت ${time} خالی شد. سریع رزرو کنید!`;
}

import { createAsyncThunk, createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type {
  WaitlistEntry,
  WaitlistNotification,
  WaitlistStatus,
} from "@/lib/data/types";
import { mockWaitlistEntries } from "@/lib/data/mock/waitlist";
import {
  formatWaitlistMessage,
  nextWaitingEntry,
  recalculateQueuePositions,
} from "@/lib/waitlist/waitlistEngine";
import { updateAppointmentStatus } from "@/store/slices/adminSlice";
import type { RootState } from "@/store";

interface WaitlistState {
  entries: WaitlistEntry[];
  notifications: WaitlistNotification[];
}

const initialState: WaitlistState = {
  entries: mockWaitlistEntries.map((e) => ({ ...e })),
  notifications: [],
};

export const cancelAppointmentWithWaitlist = createAsyncThunk(
  "waitlist/cancelAppointmentWithWaitlist",
  async (appointmentId: string, { dispatch, getState }) => {
    const state = getState() as RootState;
    const appointment = state.admin.appointments.find((a) => a.id === appointmentId);
    if (!appointment) return null;

    dispatch(updateAppointmentStatus({ id: appointmentId, status: "cancelled" }));
    dispatch(
      notifyWaitlistForSlot({
        staffId: appointment.staffId,
        staffName: appointment.staffName,
        serviceId: appointment.serviceId,
        serviceName: appointment.serviceName,
        date: appointment.date,
        time: appointment.time,
      })
    );

    return appointment;
  }
);

const waitlistSlice = createSlice({
  name: "waitlist",
  initialState,
  reducers: {
    joinWaitlist: (
      state,
      action: PayloadAction<Omit<WaitlistEntry, "id" | "status" | "queuePosition" | "notifiedAt" | "createdAt">>
    ) => {
      const { staffId, date, time } = action.payload;
      const duplicate = state.entries.find(
        (e) =>
          e.customerId === action.payload.customerId &&
          e.staffId === staffId &&
          e.date === date &&
          e.time === time &&
          (e.status === "waiting" || e.status === "notified")
      );
      if (duplicate) return;

      const waitingCount = state.entries.filter(
        (e) =>
          e.staffId === staffId &&
          e.date === date &&
          e.time === time &&
          e.status === "waiting"
      ).length;

      const entry: WaitlistEntry = {
        ...action.payload,
        id: `wl_${Date.now()}`,
        status: "waiting",
        queuePosition: waitingCount + 1,
        notifiedAt: null,
        createdAt: new Date().toISOString(),
      };
      state.entries.unshift(entry);
    },
    notifyWaitlistForSlot: (
      state,
      action: PayloadAction<{
        staffId: string;
        staffName: string;
        serviceId: string;
        serviceName: string;
        date: string;
        time: string;
      }>
    ) => {
      const { staffId, staffName, serviceId, serviceName, date, time } =
        action.payload;

      const next = nextWaitingEntry(state.entries, staffId, date, time);
      if (!next) return;

      next.status = "notified";
      next.notifiedAt = new Date().toISOString();

      const notification: WaitlistNotification = {
        id: `wn_${Date.now()}`,
        waitlistEntryId: next.id,
        customerId: next.customerId,
        staffId,
        staffName,
        serviceId,
        serviceName,
        date,
        time,
        message: formatWaitlistMessage(staffName, serviceName, date, time),
        read: false,
        createdAt: new Date().toISOString(),
      };
      state.notifications.unshift(notification);

      recalculateQueuePositions(state.entries, staffId, date, time);
    },
    markWaitlistNotificationRead: (state, action: PayloadAction<string>) => {
      const n = state.notifications.find((x) => x.id === action.payload);
      if (n) n.read = true;
    },
    claimWaitlistSlot: (state, action: PayloadAction<string>) => {
      const entry = state.entries.find((e) => e.id === action.payload);
      if (entry) {
        entry.status = "claimed";
        const n = state.notifications.find((x) => x.waitlistEntryId === entry.id);
        if (n) n.read = true;
      }
    },
    cancelWaitlistEntry: (state, action: PayloadAction<string>) => {
      const entry = state.entries.find((e) => e.id === action.payload);
      if (!entry || entry.status === "claimed") return;
      const { staffId, date, time } = entry;
      entry.status = "cancelled";
      recalculateQueuePositions(state.entries, staffId, date, time);
    },
    updateWaitlistEntryStatus: (
      state,
      action: PayloadAction<{ id: string; status: WaitlistStatus }>
    ) => {
      const entry = state.entries.find((e) => e.id === action.payload.id);
      if (entry) entry.status = action.payload.status;
    },
  },
});

export const {
  joinWaitlist,
  notifyWaitlistForSlot,
  markWaitlistNotificationRead,
  claimWaitlistSlot,
  cancelWaitlistEntry,
  updateWaitlistEntryStatus,
} = waitlistSlice.actions;

export const selectAllWaitlistEntries = (state: { waitlist: WaitlistState }) =>
  [...state.waitlist.entries].sort((a, b) => b.createdAt.localeCompare(a.createdAt));

export const selectActiveWaitlistEntries = (state: { waitlist: WaitlistState }) =>
  state.waitlist.entries.filter(
    (e) => e.status === "waiting" || e.status === "notified"
  );

export const selectWaitlistNotificationsForCustomer =
  (customerId: string) => (state: { waitlist: WaitlistState }) =>
    state.waitlist.notifications.filter((n) => n.customerId === customerId);

export const selectUnreadWaitlistNotificationsForCustomer =
  (customerId: string) => (state: { waitlist: WaitlistState }) =>
    state.waitlist.notifications.filter(
      (n) => n.customerId === customerId && !n.read
    );

export const selectWaitlistStats = (state: { waitlist: WaitlistState }) => {
  const entries = state.waitlist.entries;
  return {
    total: entries.filter((e) => e.status === "waiting" || e.status === "notified").length,
    waiting: entries.filter((e) => e.status === "waiting").length,
    notified: entries.filter((e) => e.status === "notified").length,
    claimed: entries.filter((e) => e.status === "claimed").length,
    notificationsSent: state.waitlist.notifications.length,
  };
};

export const selectCustomerWaitlistEntries =
  (customerId: string) => (state: { waitlist: WaitlistState }) =>
    state.waitlist.entries.filter(
      (e) =>
        e.customerId === customerId &&
        (e.status === "waiting" || e.status === "notified")
    );

export default waitlistSlice.reducer;

