"use client";

import { motion } from "framer-motion";
import { cn } from "@/lib/cn";
import type { WaitlistEntry } from "@/lib/data/types";

interface WaitlistTableProps {
  entries: WaitlistEntry[];
  onNotify?: (entry: WaitlistEntry) => void;
  onCancel?: (id: string) => void;
}

const statusStyles: Record<WaitlistEntry["status"], string> = {
  waiting: "bg-[#E8A84C]/10 text-[#E8A84C] border-[#E8A84C]/30",
  notified: "bg-[#4CAF82]/10 text-[#4CAF82] border-[#4CAF82]/30",
  claimed: "bg-[#C9A96E]/10 text-[#C9A96E] border-[#C9A96E]/30",
  expired: "bg-[#A09880]/10 text-[#A09880] border-[#A09880]/30",
  cancelled: "bg-[#E05555]/10 text-[#E05555] border-[#E05555]/30",
};

const statusLabels: Record<WaitlistEntry["status"], string> = {
  waiting: "در صف",
  notified: "خبر داده‌شده",
  claimed: "رزرو شد",
  expired: "منقضی",
  cancelled: "لغو شده",
};

export default function WaitlistTable({ entries, onNotify, onCancel }: WaitlistTableProps) {
  if (entries.length === 0) {
    return (
      <div className="rounded-2xl bg-white/5 border border-white/10 p-12 text-center">
        <p className="text-[#A09880]">موردی در لیست انتظار نیست</p>
      </div>
    );
  }

  return (
    <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b border-[#2A2A3A]">
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">مشتری</th>
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">پرسنل / سرویس</th>
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">زمان</th>
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">صف</th>
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">وضعیت</th>
              <th className="text-right px-4 py-4 text-sm font-medium text-[#A09880]">عملیات</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#2A2A3A]">
            {entries.map((entry, i) => (
              <motion.tr
                key={entry.id}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.03 }}
                className="hover:bg-white/[0.02]"
              >
                <td className="px-4 py-4">
                  <p className="font-medium text-[#F5F0E8]">{entry.customerName}</p>
                  <p className="text-xs text-[#A09880]">{entry.customerPhone}</p>
                </td>
                <td className="px-4 py-4">
                  <p className="text-[#F5F0E8] text-sm">{entry.staffName}</p>
                  <p className="text-xs text-[#A09880]">{entry.serviceName}</p>
                </td>
                <td className="px-4 py-4 text-sm text-[#F5F0E8] whitespace-nowrap">
                  {entry.date}
                  <span className="block text-xs text-[#A09880]">{entry.time}</span>
                </td>
                <td className="px-4 py-4">
                  <span className="text-[#C9A96E] font-bold">
                    #{entry.queuePosition.toLocaleString("fa-IR")}
                  </span>
                </td>
                <td className="px-4 py-4">
                  <span
                    className={cn(
                      "px-2.5 py-1 rounded-lg text-xs font-medium border",
                      statusStyles[entry.status]
                    )}
                  >
                    {statusLabels[entry.status]}
                  </span>
                </td>
                <td className="px-4 py-4">
                  <div className="flex gap-2">
                    {entry.status === "waiting" && onNotify && (
                      <button
                        type="button"
                        onClick={() => onNotify(entry)}
                        className="px-3 py-1.5 rounded-lg text-xs bg-[#4CAF82]/10 text-[#4CAF82] hover:bg-[#4CAF82]/20 transition-colors"
                      >
                        ارسال خبر
                      </button>
                    )}
                    {(entry.status === "waiting" || entry.status === "notified") && onCancel && (
                      <button
                        type="button"
                        onClick={() => onCancel(entry.id)}
                        className="px-3 py-1.5 rounded-lg text-xs text-[#A09880] hover:text-[#E05555] transition-colors"
                      >
                        حذف
                      </button>
                    )}
                  </div>
                </td>
              </motion.tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

