"use client";

import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import { ListOrdered, BellRing, Users, CheckCircle2 } from "lucide-react";
import { cn } from "@/lib/cn";
import WaitlistTable from "@/components/admin/WaitlistTable";
import AdminFilterSelect from "@/components/admin/AdminFilterSelect";
import { useAppDispatch, useAppSelector } from "@/store/hooks";
import {
  cancelWaitlistEntry,
  notifyWaitlistForSlot,
  selectActiveWaitlistEntries,
  selectAllWaitlistEntries,
  selectWaitlistStats,
} from "@/store/slices/waitlistSlice";

export default function WaitlistPage() {
  const dispatch = useAppDispatch();
  const allEntries = useAppSelector(selectAllWaitlistEntries);
  const activeEntries = useAppSelector(selectActiveWaitlistEntries);
  const stats = useAppSelector(selectWaitlistStats);
  const [statusFilter, setStatusFilter] = useState("");

  const filtered = useMemo(() => {
    if (!statusFilter) return allEntries;
    return allEntries.filter((e) => e.status === statusFilter);
  }, [allEntries, statusFilter]);

  const statCards = [
    {
      label: "در صف",
      value: stats.waiting,
      icon: ListOrdered,
      color: "text-[#E8A84C]",
      bg: "bg-[#E8A84C]/10",
    },
    {
      label: "خبر داده‌شده",
      value: stats.notified,
      icon: BellRing,
      color: "text-[#4CAF82]",
      bg: "bg-[#4CAF82]/10",
    },
    {
      label: "رزرو شده",
      value: stats.claimed,
      icon: CheckCircle2,
      color: "text-[#C9A96E]",
      bg: "bg-[#C9A96E]/10",
    },
    {
      label: "کل فعال",
      value: stats.total,
      icon: Users,
      color: "text-[#3B82F6]",
      bg: "bg-[#3B82F6]/10",
    },
  ];

  const handleManualNotify = (entry: (typeof activeEntries)[0]) => {
    dispatch(
      notifyWaitlistForSlot({
        staffId: entry.staffId,
        staffName: entry.staffName,
        serviceId: entry.serviceId,
        serviceName: entry.serviceName,
        date: entry.date,
        time: entry.time,
      })
    );
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((card, i) => (
          <motion.div
            key={card.label}
            initial={{ opacity: 0, y: 16 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="rounded-2xl bg-white/5 border border-white/10 p-4"
          >
            <div className={cn("w-9 h-9 rounded-lg flex items-center justify-center mb-2", card.bg)}>
              <card.icon size={18} className={card.color} />
            </div>
            <p className="text-2xl font-bold text-[#F5F0E8]">
              {card.value.toLocaleString("fa-IR")}
            </p>
            <p className="text-xs text-[#A09880] mt-1">{card.label}</p>
          </motion.div>
        ))}
      </div>

      <div className="rounded-2xl bg-white/5 border border-white/10 p-4">
        <h3 className="text-sm font-bold text-[#F5F0E8] mb-2">چطور کار می‌کند؟</h3>
        <p className="text-xs text-[#A09880] leading-relaxed">
          مشتری روی ساعت پر کلیک می‌کند و وارد صف می‌شود. وقتی نوبتی در همان بازه{" "}
          <span className="text-[#C9A96E]">لغو</span> شود، نفر اول صف{" "}
          <span className="text-[#4CAF82]">اتوماتیک</span> مطلع می‌شود — ظرفیت از دست
          رفته recover می‌شود.
        </p>
        <p className="text-xs text-[#A09880] mt-2">
          دمو: نوبت a9 (علی احمدی — ۱۴۰۳/۱۰/۲۰ ۱۰:۰۰) را در نوبت‌ها لغو کنید → مریم
          رضایی (نفر ۱ صف) خبر می‌گیرد.
        </p>
      </div>

      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/10"
      >
        <AdminFilterSelect
          value={statusFilter}
          onChange={setStatusFilter}
          aria-label="فیلتر وضعیت"
          minWidth="min-w-[170px]"
          options={[
            { value: "", label: "همه وضعیت‌ها" },
            { value: "waiting", label: "در صف" },
            { value: "notified", label: "خبر داده‌شده" },
            { value: "claimed", label: "رزرو شده" },
            { value: "cancelled", label: "لغو شده" },
          ]}
        />
      </motion.div>

      <WaitlistTable
        entries={filtered}
        onNotify={handleManualNotify}
        onCancel={(id) => dispatch(cancelWaitlistEntry(id))}
      />
    </div>
  );
}

